INSERT INTO `wp_options` VALUES (824,'stellarwp_telemetry_user_info','a:1:{s:4:\"user\";s:1283:\"{\"name\":\"Babacar\",\"email\":\"dev-email@wpengine.local\",\"plugin_slug\":\"solid-security\",\"opt_in_text\":\"Bonjour Babacar, SolidWP s\\u2019engage \\u00e0 fournir des services de premier ordre, et vos commentaires nous aident \\u00e0 tenir cette promesse. En participant \\u00e0 notre programme de r\\u00e9troaction, vous contribuez \\u00e0 am\\u00e9liorer l\\u2019exp\\u00e9rience de Solid Security pour vous et tous nos utilisateurs. Lorsque vous choisissez de participer, vous nous permettez d\\u2019acc\\u00e9der \\u00e0 certaines donn\\u00e9es relatives \\u00e0 la fa\\u00e7on dont vous utilisez nos produits, que nous utilisons de mani\\u00e8re responsable pour adapter nos produits \\u00e0 vos besoins. Vous recevrez en outre des mises \\u00e0 jour, des informations importantes sur les produits et le marketing, ainsi que des offres exclusives par e-mail. Vous pouvez vous d\\u00e9sabonner \\u00e0 tout moment. Nous prenons la confidentialit\\u00e9 des donn\\u00e9es au s\\u00e9rieux et adh\\u00e9rons aux normes les plus \\u00e9lev\\u00e9es en respectant toutes les r\\u00e9glementations et lignes directrices pertinentes. Pour vous inscrire et contribuer \\u00e0 fa\\u00e7onner l\\u2019avenir de Solid Security et de StellarWP, cliquez simplement sur \\u00ab\\u00a0Autoriser et continuer\\u00a0\\u00bb ci-dessous.\"}\";}','off');
