INSERT INTO `wp_posts` VALUES (106,1,'2026-03-26 14:56:40','2026-03-26 14:56:40','<!-- wp:paragraph -->\n<p><strong>Télécharge tes cours en un clic</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Plus besoin de chercher partout : tous les cours PDF sont centralisés et faciles à obtenir.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>Partage et enrichis la bibliothèque</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Contribue à la communauté en ajoutant tes propres cours et aides.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p><strong>Étudie efficacement et reste organisé</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Classe es cours par matière, retrouve-les rapidement et révise sans stress</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:image {\"id\":101} -->\n<figure class=\"wp-block-image\"><img src=\"http://supboost.local/wp-content/uploads/2026/03/Gemini_Generated_Image_iudy9wiudy9wiudy-1-edited.png\" alt=\"\" class=\"wp-image-101\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:verse -->\n<pre class=\"wp-block-verse\"></pre>\n<!-- /wp:verse -->','Étudier n’a Jamais Été Aussi Facile avec Supboost','','publish','open','open','','etudier-na-jamais-ete-aussi-facile-avec-supboost','','','2026-03-26 14:56:40','2026-03-26 14:56:40','',0,'http://supboost.local/?p=106',0,'post','',0);
