INSERT INTO `wp_posts` VALUES (108,1,'2026-03-26 15:13:45','2026-03-26 15:13:45','<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\",\"fontSize\":\"medium\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color has-medium-font-size\">Supboost est <strong>la plateforme pratique pour tous les étudiants en informatique</strong>. Télécharge et partage tes cours dans <strong>tous les domaines de l’enseignement supérieur</strong> : programmation, réseaux, bases de données, intelligence artificielle, et plus encore.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-6\"}}}},\"textColor\":\"ast-global-color-6\"} -->\n<p class=\"has-ast-global-color-6-color has-text-color has-link-color\">Avec Supboost, tu peux :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-2\"}}}},\"textColor\":\"ast-global-color-2\"} -->\n<li class=\"has-ast-global-color-2-color has-text-color has-link-color\"><strong>Accéder rapidement aux cours PDF</strong> dont tu as besoin</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-2\"}}}},\"textColor\":\"ast-global-color-2\"} -->\n<li class=\"has-ast-global-color-2-color has-text-color has-link-color\"><strong>Uploader tes propres documents</strong> pour aider la communauté</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-2\"}}}},\"textColor\":\"ast-global-color-2\"} -->\n<li class=\"has-ast-global-color-2-color has-text-color has-link-color\"><strong>Organiser tes études efficacement</strong> et progresser à ton rythme</li>\n<!