INSERT INTO `wp_posts` VALUES (148,1,'2026-03-28 09:35:17','2026-03-28 09:35:17','<!-- wp:paragraph {\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\">Supboost est <strong>la plateforme pratique pour tous les étudiants en informatique</strong>. Télécharge et partage tes cours dans <strong>tous les domaines de l’enseignement supérieur</strong> : programmation, réseaux, bases de données, intelligence artificielle, et plus encore.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Avec Supboost, tu peux :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Accéder rapidement aux cours PDF</strong> dont tu as besoin</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Uploader tes propres documents</strong> pour aider la communauté</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Organiser tes études efficacement</strong> et progresser à ton rythme</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"fontSize\":\"large\"} -->\n<p class=\"has-large-font-size\"><strong>Commence dès maintenant et booste tes études avec Supboost !</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons {\"align\":\"wide\",\"style\":{\"spacing\":{\"padding\":{\"top\":\"0\",\"bottom\":\"0\",\"left\":\"0\",\"right\":\"0\"},\"blockGap\":{\"top\":\"0\"}},\"border\":{\"radius\":{\"topLeft\":\"25px\",\"topRight\":\"25px\",\"bottomLeft\":\"25px\",\"bottomRight\":\"25px\"},\"width\":\"0px\",\"style\":\"none\"}},\"fontSize\":\"large\",\"layout\":{\"type\":\"flex\",\"justifyContent\":\"center\"}} -->\n<div class=\"wp-block-buttons alignwide has-custom-font-size has-large-font-size\" style=\"border-style:none;border-width:0px;border-top-left-radius:25px;border-top-right-radius:25px;border-bottom-left-radius:25px;border-bottom-right-radius:25px;padding-top:0;padding-right:0;padding-bottom:0;padding-left:0\"><!-- wp:button {\"className\":\"is-style-fill\"} -->\n<div class=\"wp-block-button is-style-fill\"><a class=\"wp-block-button__link wp-element-button\" href=\"http://supboost.local/choisissez-vos-domaines-detudes/\">commencer l\'expérience</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Supboost','','inherit','closed','closed','','108-revision-v1','','','2026-03-28 09:35:17','2026-03-28 09:35:17','',108,'http://supboost.local/?p=148',0,'revision','',0);
