INSERT INTO `wp_posts` VALUES (162,1,'2026-03-28 18:51:30','2026-03-28 18:51:30','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\"><strong>Qui sommes-nous ?</strong></h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Supboost est une plateforme conçue pour les étudiants souhaitant accéder facilement à des ressources pédagogiques de qualité. Le site permet de télécharger et partager des cours dans différents domaines des études supérieures, avec un accent particulier sur l’informatique.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Notre objectif</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Notre objectif est simple : faciliter l’accès au savoir et encourager le partage entre étudiants. Supboost vise à centraliser les cours afin d’aider chacun à mieux comprendre, réviser et réussir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Ce que vous pouvez faire sur Supboost</h2>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Télécharger des cours rapidement</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Partager vos propres documents</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Accéder à des ressources organisées par domaine</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Trouver des supports utiles pour vos études</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">À qui s’adresse Supboost ?</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Supboost s’adresse principalement :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>aux étudiants en informatique</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>aux étudiants du supérieur</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>à toute personne souhaitant apprendre et progresser</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Nos valeurs</h2>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Partage du savoir</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Entraide entre étudiants</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Accessibilité pour tous</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Rejoignez-nous</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Commencez dès maintenant à explorer les ressources ou partagez vos propres cours pour aider la communauté.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:image -->\n<figure class=\"wp-block-image\"><img alt=\"\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button -->\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\">commencer l\'expérience </a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons -->','À propos de Supboost','','inherit','closed','closed','','156-revision-v1','','','2026-03-28 18:51:30','2026-03-28 18:51:30','',156,'http://supboost.local/?p=162',0,'revision','',0);
