INSERT INTO `wp_posts` VALUES (164,1,'2026-03-28 18:51:31','2026-03-28 18:51:31','<h2>Ajoutez votre titre ici<h3 data-start=\"213\" data-end=\"230\">Notre Mission</h3>\n<p data-start=\"231\" data-end=\"420\"><strong data-start=\"231\" data-end=\"243\">Supboost</strong> accompagne les étudiants dans leur parcours académique pour faciliter la réussite scolaire. Nous proposons des ressources claires, accessibles et adaptées à tous les niveaux.</p>\n<h3 data-start=\"422\" data-end=\"437\">Nos Valeurs</h3>\n<ul data-start=\"438\" data-end=\"683\">\n<li data-start=\"438\" data-end=\"516\">\n<strong data-start=\"440\" data-end=\"454\">Simplicité</strong> : Apprendre sans se perdre dans des informations complexes.\n</li>\n<li data-start=\"517\" data-end=\"588\">\n<strong data-start=\"519\" data-end=\"536\">Accessibilité</strong> : Du contenu disponible pour tous, à tout moment.\n</li>\n<li data-start=\"589\" data-end=\"683\">\n<strong data-start=\"591\" data-end=\"602\">Progrès</strong> : Des outils et méthodes pour avancer à son rythme et atteindre ses objectifs.\n</li>\n</ul>\n<h3 data-start=\"685\" data-end=\"710\">Ce que nous proposons</h3>\n<ul data-start=\"711\" data-end=\"884\">\n<li data-start=\"711\" data-end=\"766\">\nContenus organisés par <strong data-start=\"736\" data-end=\"748\">matières</strong> et <strong data-start=\"752\" data-end=\"763\">niveaux</strong>.\n</li>\n<li data-start=\"767\" data-end=\"833\">\nExercices pratiques et projets pour renforcer vos compétences.\n</li>\n<li data-start=\"834\" data-end=\"884\">\nRessources pédagogiques modernes et efficaces.\n</li>\n</ul>\n<h3 data-start=\"886\" data-end=\"906\">Notre Engagement</h3>\n<p data-start=\"907\" data-end=\"1041\">Notre équipe s’engage à améliorer constamment votre expérience sur Supboost, pour que l’apprentissage devienne motivant et efficace.</p>\n<h3 data-start=\"1043\" data-end=\"1061\">Rejoignez-nous</h3>\n<p data-start=\"1062\" data-end=\"1169\">Découvrez une nouvelle manière d’apprendre, où chaque étudiant peut progresser et réussir avec confiance.</p>\n</h2>','À propos de Supboost','','inherit','closed','closed','','156-revision-v1','','','2026-03-28 18:51:31','2026-03-28 18:51:31','',156,'http://supboost.local/?p=164',0,'revision','',0);
