INSERT INTO `wp_posts` VALUES (183,1,'2026-03-28 19:36:28','2026-03-28 19:36:28','<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Notre Mission</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Supboost</strong> accompagne les étudiants dans leur parcours académique pour faciliter la réussite scolaire. Nous proposons des ressources claires, accessibles et adaptées à tous les niveaux.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Nos Valeurs</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Simplicité</strong> : Apprendre sans se perdre dans des informations complexes.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Accessibilité</strong> : Du contenu disponible pour tous, à tout moment.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Progrès</strong> : Des outils et méthodes pour avancer à son rythme et atteindre ses objectifs.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Ce que nous proposons</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Contenus organisés par <strong>matières</strong> et <strong>niveaux</strong>.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Exercices pratiques et projets pour renforcer vos compétences.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Ressources pédagogiques modernes et efficaces.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Notre Engagement</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Notre équipe s’engage à améliorer constamment votre expérience sur Supboost, pour que l’apprentissage devienne motivant et efficace.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Rejoignez-nous</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"large\"} -->\n<p class=\"has-large-font-size\">Découvrez une nouvelle manière d’apprendre, où chaque étudiant peut progresser et réussir avec confiance.</p>\n<!-- /wp:paragraph -->','A propos de Supboost','','inherit','closed','closed','','170-revision-v1','','','2026-03-28 19:36:28','2026-03-28 19:36:28','',170,'http://supboost.local/?p=183',0,'revision','',0);
