INSERT INTO `wp_posts` VALUES (196,1,'2026-03-29 10:58:34','2026-03-29 10:58:34','<!-- wp:heading {\"textAlign\":\"left\",\"level\":3} -->\n<h3 class=\"wp-block-heading has-text-align-left\">Notre Mission</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"align\":\"left\",\"fontSize\":\"medium\"} -->\n<p class=\"has-text-align-left has-medium-font-size\"><strong>Supboost</strong> accompagne les étudiants dans leur parcours académique pour faciliter la réussite scolaire. Nous proposons des ressources claires, accessibles et adaptées à tous les niveaux.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Nos Valeurs</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"medium\"} -->\n<li class=\"has-medium-font-size\"><strong>Simplicité</strong> : Apprendre sans se perdre dans des informations complexes.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"medium\"} -->\n<li class=\"has-medium-font-size\"><strong>Accessibilité</strong> : Du contenu disponible pour tous, à tout moment.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"medium\"} -->\n<li class=\"has-medium-font-size\"><strong>Progrès</strong> : Des outils et méthodes pour avancer à son rythme et atteindre ses objectifs.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Ce que nous proposons</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"medium\"} -->\n<li class=\"has-medium-font-size\">Contenus organisés par <strong>matières</strong> et <strong>niveaux</strong>.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"medium\"} -->\n<li class=\"has-medium-font-size\">Exercices pratiques et projets pour renforcer vos compétences.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"medium\"} -->\n<li class=\"has-medium-font-size\">Ressources pédagogiques modernes et efficaces.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Notre Engagement</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\">Notre équipe s’engage à améliorer constamment votre expérience sur Supboost, </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\">pour que l’apprentissage devienne motivant et efficace.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Rejoignez-nous</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"large\"} -->\n<p class=\"has-large-font-size\">Découvrez une nouvelle manière d’apprendre, </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\">où chaque étudiant peut progresser et réussir avec confiance.</p>\n<!-- /wp:paragraph -->','A propos de Supboost','','inherit','closed','closed','','170-revision-v1','','','2026-03-29 10:58:34','2026-03-29 10:58:34','',170,'http://supboost.local/?p=196',0,'revision','',0);
