INSERT INTO `wp_posts` VALUES (214,1,'2026-03-29 17:26:27','2026-03-29 17:26:27','<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-6\"}}}},\"textColor\":\"ast-global-color-6\"} -->\n<p class=\"has-ast-global-color-6-color has-text-color has-link-color\">Une question, un problème ou besoin d\'aide concernant Supboost?</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-6\"}}}},\"textColor\":\"ast-global-color-6\"} -->\n<p class=\"has-ast-global-color-6-color has-text-color has-link-color\">Notre équipe est là pour vous répondre rapidement</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-6\"}}}},\"textColor\":\"ast-global-color-6\",\"fontSize\":\"large\"} -->\n<p class=\"has-ast-global-color-6-color has-text-color has-link-color has-large-font-size\">Envoyez nous un message</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:shortcode -->\n[contact-form-7 id=\"e25c4ab\" title=\"Formulaire de contact 1\"]\n<!-- /wp:shortcode -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-6\"}}}},\"textColor\":\"ast-global-color-6\"} -->\n<p class=\"has-ast-global-color-6-color has-text-color has-link-color\">Vous pouvez aussi nous contacter via</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-6\"}}}},\"textColor\":\"ast-global-color-6\"} -->\n<p class=\"has-ast-global-color-6-color has-text-color has-link-color\">Téléphone: 76-939-74-72 ou au 70- 518- 59 -06</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-6\"}}}},\"textColor\":\"ast-global-color-6\"} -->\n<p class=\"has-ast-global-color-6-color has-text-color has-link-color\">E-mail: dionebabacar025@gmail.com </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-6\"}}}},\"textColor\":\"ast-global-color-6\"} -->\n<p class=\"has-ast-global-color-6-color has-text-color has-link-color\">Adresse: Dakar, Sénégal</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-6\"}}}},\"textColor\":\"ast-global-color-6\"} -->\n<p class=\"has-ast-global-color-6-color has-text-color has-link-color\">Horaire: Lundi- Samedi: 10h-17h</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Contactez-nous','','publish','closed','closed','','contactez-nous','','','2026-03-30 20:37:14','2026-03-30 20:37:14','',0,'http://supboost.local/?page_id=214',0,'page','',0);
INSERT INTO `wp_posts` VALUES (215,1,'2026-03-29 16:51:07','2026-03-29 16:51:07','<!-- wp:paragraph -->\n<p>Une question, un problème ou besoin d\'aide concernant Supboost?</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Notre équipe est là pour vous répondre rapidement</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"large\"} -->\n<p class=\"has-large-font-size\">Envoyez nous un message</p>\n<!-- /wp:paragraph -->','Contactez-nous','','inherit','closed','closed','','214-revision-v1','','','2026-03-29 16:51:07','2026-03-29 16:51:07','',214,'http://supboost.local/?p=215',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (216,1,'2026-03-29 16:53:29','2026-03-29 16:53:29','<label> Votre nom\n    [text* your-name autocomplete:name] </label>\n\n<label> Votre e-mail\n    [email* your-email autocomplete:email] </label>\n\n<label> Objet\n    [text* your-subject] </label>\n\n<label> Votre message (facultatif)\n    [textarea your-message] </label>\n\n[submit \"Envoyer\"]\n[_site_title] \"[your-subject]\"\n[_site_title] <wordpress@supboost.local>\nDe : [your-name] [your-email]\nObjet : [your-subject]\n\nCorps du message :\n[your-message]\n\n-- \nCeci est une notification qu’un formulaire de contact a été envoyé sur votre site web ([_site_title] [_site_url]).\n[_site_admin_email]\nReply-To: [your-email]\n\n0\n0\n\n[_site_title] \"[your-subject]\"\n[_site_title] <wordpress@supboost.local>\nCorps du message :\n[your-message]\n\n-- \nCet e-mail est un accusé de réception du formulaire de contact que vous avez envoyé sur notre site web ([_site_title] [_site_url]) et dans lequel votre adresse e-mail a été utilisée. Si ce n’est pas vous, veuillez ignorer ce message.\n[your-email]\nReply-To: [_site_admin_email]\n\n0\n0\nMerci pour votre message. Il a été envoyé.\nUne erreur s’est produite lors de l’envoi de votre message. Veuillez essayer à nouveau plus tard.\nUn ou plusieurs champs contiennent une erreur. Veuillez vérifier et essayer à nouveau.\nUne erreur s’est produite lors de l’envoi de votre message. Veuillez essayer à nouveau plus tard.\nVous devez accepter les termes et conditions avant d’envoyer votre message.\nVeuillez renseigner ce champ.\nCe champ a une saisie trop longue.\nCe champ a une saisie trop courte.\nUne erreur inconnue s’est produite lors du téléversement du fichier.\nVous n’avez pas les droits nécessaires pour téléverser ce type de fichier.\nLe fichier téléversé est trop volumineux.\nUne erreur s’est produite lors du téléversement du fichier.','Formulaire de contact 1','','publish','closed','closed','','formulaire-de-contact-1','','','2026-03-29 16:53:29','2026-03-29 16:53:29','',0,'http://supboost.local/?post_type=wpcf7_contact_form&p=216',0,'wpcf7_contact_form','',0);
