INSERT INTO `wp_posts` VALUES (222,1,'2026-03-29 17:39:57','2026-03-29 17:39:57','<!-- wp:cover {\"url\":\"http://supboost.local/wp-content/uploads/2026/03/Gemini_Generated_Image_mib7z5mib7z5mib7-1024x559.png\",\"id\":168,\"dimRatio\":50,\"style\":{\"color\":[]}} -->\n<div class=\"wp-block-cover\"><img class=\"wp-block-cover__image-background wp-image-168\" alt=\"\" src=\"http://supboost.local/wp-content/uploads/2026/03/Gemini_Generated_Image_mib7z5mib7z5mib7-1024x559.png\" data-object-fit=\"cover\"/><span aria-hidden=\"true\" class=\"wp-block-cover__background has-background-dim\"></span><div class=\"wp-block-cover__inner-container\"><!-- wp:paragraph {\"align\":\"center\",\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"#f10a0a\"}}},\"color\":{\"text\":\"#f10a0a\"}},\"fontSize\":\"large\"} -->\n<p class=\"has-text-align-center has-text-color has-link-color has-large-font-size\" style=\"color:#f10a0a\">Notre Mission</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"left\",\"fontSize\":\"medium\"} -->\n<p class=\"has-text-align-left has-medium-font-size\"><strong>Supboost</strong> accompagne les étudiants dans leur parcours académique pour faciliter la réussite scolaire. </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"left\",\"fontSize\":\"medium\"} -->\n<p class=\"has-text-align-left has-medium-font-size\">Nous proposons des ressources claires, accessibles et adaptées à tous les niveaux.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"#e90f0f\"}}},\"color\":{\"text\":\"#e90f0f\"}}} -->\n<h3 class=\"wp-block-heading has-text-color has-link-color\" style=\"color:#e90f0f\">Nos Valeurs</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"medium\"} -->\n<li class=\"has-medium-font-size\"><strong>Simplicité</strong> : Apprendre sans se perdre dans des informations complexes.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"medium\"} -->\n<li class=\"has-medium-font-size\"><strong>Accessibilité</strong> : Du contenu disponible pour tous, à tout moment.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"medium\"} -->\n<li class=\"has-medium-font-size\"><strong>Progrès</strong> : Des outils et méthodes pour avancer à son rythme et atteindre ses objectifs.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3,\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"#f70707\"}}},\"color\":{\"text\":\"#f70707\"}}} -->\n<h3 class=\"wp-block-heading has-text-color has-link-color\" style=\"color:#f70707\">Ce que nous proposons</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item {\"fontSize\":\"medium\"} -->\n<li class=\"has-medium-font-size\">Contenus organisés par <strong>matières</strong> et <strong>niveaux</strong>.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"medium\"} -->\n<li class=\"has-medium-font-size\">Exercices pratiques et projets pour renforcer vos compétences.</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item {\"fontSize\":\"medium\"} -->\n<li class=\"has-medium-font-size\">Ressources pédagogiques modernes et efficaces.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3,\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"#ed0707\"}}},\"color\":{\"text\":\"#ed0707\"}}} -->\n<h3 class=\"wp-block-heading has-text-color has-link-color\" style=\"color:#ed0707\">Notre Engagement</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\">Notre équipe s’engage à améliorer constamment </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\">votre expérience sur Supboost,</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\">pour que l’apprentissage devienne motivant et efficace.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3,\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"#f40c0c\"}}},\"color\":{\"text\":\"#f40c0c\"}}} -->\n<h3 class=\"wp-block-heading has-text-color has-link-color\" style=\"color:#f40c0c\">Rejoignez-nous</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph {\"fontSize\":\"medium\"} -->\n<p class=\"has-medium-font-size\">Découvrez une nouvelle manière d’apprendre, </p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"align\":\"center\",\"fontSize\":\"large\"} -->\n<p class=\"has-text-align-center has-large-font-size\">où chaque étudiant peut progresser et réussir avec confiance.</p>\n<!-- /wp:paragraph --></div></div>\n<!-- /wp:cover -->','A propos de Supboost','','publish','closed','closed','','a-propos-de-supboost','','','2026-03-29 17:48:06','2026-03-29 17:48:06','',0,'http://supboost.local/?page_id=222',0,'page','',0);
