INSERT INTO `wp_posts` VALUES (248,1,'2026-03-30 12:21:41','2026-03-30 12:21:41','<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">L’algorithme et la programmation constituent la base de l’informatique moderne. Avant de créer un programme, une application ou un site web, il est indispensable de savoir analyser un problème et construire une suite d’instructions logiques pour le résoudre. Ce cours vous permettra de développer votre raisonnement, votre esprit d’analyse et votre capacité à concevoir des solutions claires et efficaces. Vous apprendrez à structurer vos idées, à écrire des algorithmes et à les traduire en programmes informatiques.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">Maîtriser l’algorithme et la programmation, c’est acquérir les fondements nécessaires pour évoluer dans tous les domaines du numérique.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 1: introduction à l\'Algorithme</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 2: variables et types de données</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 3: les opérateurs</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 4: les structures conditionnelles</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 5: les boucles et structures itératives</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 6: les tableaux</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons -->\n\n<!-- wp:paragraph -->\n<p>Vhapi</p>\n<!-- /wp:paragraph -->','Algorithme et Programmation','','trash','closed','closed','','algorithme-et-programmation__trashed','','','2026-04-05 17:44:16','2026-04-05 17:44:16','',0,'http://supboost.local/?page_id=248',0,'page','',0);
