INSERT INTO `wp_posts` VALUES (259,1,'2026-03-30 13:56:37','2026-03-30 13:56:37','<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">Le droit est présent dans tous les aspects de la vie personnelle, professionnelle et sociale. Comprendre les principes fondamentaux du droit permet de mieux connaître ses droits, ses obligations et le fonctionnement des institutions juridiques. Ce cours vous donnera les bases essentielles pour appréhender les différentes branches du droit, comprendre les lois, les contrats et les règles qui régissent la société. Il constitue un socle indispensable pour les études juridiques, la vie professionnelle et la citoyenneté.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">Apprendre le droit, c’est acquérir un outil indispensable pour agir de manière éclairée et responsable dans la vie quotidienne et professionnelle.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 1: le droit objectif</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 2: la règle  de droit</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 3: les sources du droit</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 4: les droits subjectifs</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 5: la classification des droits subjectifs</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 6: la protection des droits subjectifs</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Introduction au droit','','publish','closed','closed','','introduction-au-droit','','','2026-04-05 12:19:41','2026-04-05 12:19:41','',0,'http://supboost.local/?page_id=259',0,'page','',0);
