INSERT INTO `wp_posts` VALUES (290,1,'2026-04-05 17:44:34','2026-04-05 17:44:34','<!-- wp:shortcode -->\n<!DOCTYPE html>\n<html lang=\"fr\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Cours 1 - Introduction à Python</title>\n  <style>\n    body {\n      font-family: Arial, sans-serif;\n      max-width: 900px;\n      margin: 40px auto;\n      padding: 20px;\n      line-height: 1.7;\n    }\n    h1, h2 { text-align: center; }\n    .download-btn {\n      display: inline-block;\n      padding: 12px 20px;\n      border: 1px solid #000;\n      text-decoration: none;\n      margin-top: 20px;\n    }\n    pre {\n      padding: 12px;\n      border: 1px solid #ccc;\n      overflow-x: auto;\n    }\n  </style>\n</head>\n<body>\n  <h1>Cours 1 : Introduction à Python</h1>\n\n  <h2>1) Qu’est-ce que Python ?</h2>\n  <p>Python est un langage de programmation simple et très utilisé.</p>\n\n  <h2>2) Premier programme</h2>\n  <pre>print(\"Bonjour\")</pre>\n\n  <a class=\"download-btn\" href=\"cours-python-lecon-1.pdf\" download>\n    Télécharger le cours en PDF\n  </a>\n</body>\n</html>\n\n<!-- /wp:shortcode -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Leçon 1: introduction à Phyton','','trash','closed','closed','','__trashed-5','','','2026-04-05 17:44:34','2026-04-05 17:44:34','',0,'http://supboost.local/?page_id=290',0,'page','',0);
INSERT INTO `wp_posts` VALUES (291,1,'2026-04-05 10:09:48','2026-04-05 10:09:48','<!-- wp:shortcode -->\n<!DOCTYPE html>\n<html lang=\"fr\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Cours 1 - Introduction à Python</title>\n  <style>\n    body {\n      font-family: Arial, sans-serif;\n      max-width: 900px;\n      margin: 40px auto;\n      padding: 20px;\n      line-height: 1.7;\n    }\n    h1, h2 { text-align: center; }\n    .download-btn {\n      display: inline-block;\n      padding: 12px 20px;\n      border: 1px solid #000;\n      text-decoration: none;\n      margin-top: 20px;\n    }\n    pre {\n      padding: 12px;\n      border: 1px solid #ccc;\n      overflow-x: auto;\n    }\n  </style>\n</head>\n<body>\n  <h1>Cours 1 : Introduction à Python</h1>\n\n  <h2>1) Qu’est-ce que Python ?</h2>\n  <p>Python est un langage de programmation simple et très utilisé.</p>\n\n  <h2>2) Premier programme</h2>\n  <pre>print(\"Bonjour\")</pre>\n\n  <a class=\"download-btn\" href=\"cours-python-lecon-1.pdf\" download>\n    Télécharger le cours en PDF\n  </a>\n</body>\n</html>\n\n<!-- /wp:shortcode -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Leçon 1: introduction à Phyton','','inherit','closed','closed','','290-revision-v1','','','2026-04-05 10:09:48','2026-04-05 10:09:48','',290,'http://supboost.local/?p=291',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (293,1,'2026-04-05 10:28:43','2026-04-05 10:28:43','<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">Dans un monde de plus en plus numérique, la maîtrise de la programmation est devenue un véritable atout. Python, grâce à sa simplicité et à sa puissance, est aujourd’hui l’un des langages les plus demandés dans les domaines du développement web, de l’analyse de données, de l’intelligence artificielle et de la création d’applications.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-6\"}}}},\"textColor\":\"ast-global-color-6\"} -->\n<p class=\"has-ast-global-color-6-color has-text-color has-link-color\">Ce cours vous permettra de construire des bases solides en programmation, même si vous débutez totalement. À travers des explications claires et des exemples pratiques, vous développerez progressivement les compétences nécessaires pour comprendre, écrire et maîtriser vos premiers programmes. Commencer par Python, c’est faire le choix d’un apprentissage moderne, utile et porteur d’avenir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 1: introduction à Phyton </a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"className\":\"is-style-fill\",\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100 is-style-fill\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 2: variables et types de données</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 3: Entrée/sortie dans phyton</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 4: les opérateurs</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 5: les structures de conditions</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 6: les boucles</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 7: les listes</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 8: les dictionnaires</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons -->','phyton','','inherit','closed','closed','','253-revision-v1','','','2026-04-05 10:28:43','2026-04-05 10:28:43','',253,'http://supboost.local/?p=293',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (295,1,'2026-04-05 10:41:31','2026-04-05 10:41:31','<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">À l’ère du numérique, les données occupent une place centrale dans le fonctionnement des sites web, des applications et des systèmes informatiques. Les bases de données permettent de stocker, organiser, sécuriser et retrouver rapidement les informations essentielles, telles que les comptes utilisateurs, les messages, les produits ou les résultats scolaires. Maîtriser les bases de données est une compétence fondamentale pour comprendre comment les informations sont gérées dans un environnement informatique moderne. Ce cours vous aidera à acquérir des notions solides et pratiques pour mieux concevoir, manipuler et exploiter les données.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">Apprendre les bases de données, c’est se doter d’un savoir indispensable pour le développement web et l’informatique en général.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 1: introduction aux bases de données et à la modélisation</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 2: algèbre relationnel </a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 3:</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 4:</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons -->','Base de données','','inherit','closed','closed','','270-revision-v1','','','2026-04-05 10:41:31','2026-04-05 10:41:31','',270,'http://supboost.local/?p=295',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (297,1,'2026-04-05 10:55:12','2026-04-05 10:55:12','<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/microsoft-word/\">Microsoft Word</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Microsoft Excel</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons -->','Bureautique','','inherit','closed','closed','','264-autosave-v1','','','2026-04-05 10:55:12','2026-04-05 10:55:12','',264,'http://supboost.local/?p=297',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (299,1,'2026-04-05 10:57:51','2026-04-05 10:57:51','<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">La maîtrise de Microsoft Word est une compétence essentielle dans le parcours scolaire et professionnel. Ce logiciel permet de rédiger, mettre en forme et présenter des documents de manière claire, soignée et professionnelle. Grâce à ce cours, vous apprendrez à créer des devoirs, exposés, rapports, lettres, CV et fascicules avec une mise en page structurée et attractive. Vous découvrirez également comment utiliser les outils indispensables tels que les titres, tableaux, images, numérotation, en-têtes, pieds de page et la conversion en PDF.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">Maîtriser Word, c’est améliorer la qualité de vos travaux et gagner en efficacité dans la présentation de vos documents.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 1: introduction à la Bureautique</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 2: présentation de Microsoft Word</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 3: Saisie et modification de texte</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 4: Mise en forme  de texte</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 5: mise  en page  et mise en forme de paragraphe</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 6: Insertion d\'objets</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 7: création de Tableaux</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 8: En tête et Pied de Page</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 9 : création de Facture Pro format</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 10: Création d\'une lettre et le Publipostage</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons -->','Microsoft Word','','inherit','closed','closed','','267-revision-v1','','','2026-04-05 10:57:51','2026-04-05 10:57:51','',267,'http://supboost.local/?p=299',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (300,1,'2026-04-05 12:05:09','2026-04-05 12:05:09','<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">L’algorithme et la programmation constituent la base de l’informatique moderne. Avant de créer un programme, une application ou un site web, il est indispensable de savoir analyser un problème et construire une suite d’instructions logiques pour le résoudre. Ce cours vous permettra de développer votre raisonnement, votre esprit d’analyse et votre capacité à concevoir des solutions claires et efficaces. Vous apprendrez à structurer vos idées, à écrire des algorithmes et à les traduire en programmes informatiques.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">Maîtriser l’algorithme et la programmation, c’est acquérir les fondements nécessaires pour évoluer dans tous les domaines du numérique.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 1: introduction à l\'Algorithme</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 2: variables et types de données</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 3: les opérateurs</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 4: les structures conditionnelles</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 5: les boucles et structures itératives</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 6: les tableaux</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons -->\n\n<!-- wp:paragraph -->\n<p>Vhapi</p>\n<!-- /wp:paragraph -->','Algorithme et Programmation','','inherit','closed','closed','','248-revision-v1','','','2026-04-05 12:05:09','2026-04-05 12:05:09','',248,'http://supboost.local/?p=300',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (302,1,'2026-04-05 12:09:15','2026-04-05 12:09:15','<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">MERISE est une méthode essentielle dans le domaine de l’analyse et de la conception des systèmes d’information. Elle permet de structurer de manière claire l’organisation des données, des traitements et des processus d’un projet informatique. À travers ce cours, vous apprendrez à modéliser les données et les flux d’information à l’aide d’outils tels que le <strong>MCD (Modèle Conceptuel de Données)</strong>, le <strong>MLD (Modèle Logique de Données)</strong> et les différents schémas d’analyse.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">Maîtriser MERISE, c’est acquérir une base solide pour concevoir des bases de données et comprendre l’architecture d’un système informatique de manière professionnelle.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 1: Les principes de base de MERISE</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 2: Le Modèle Conceptuel de Traitement (M.C.T)</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 3: Le Modèle Conceptuel de Données (M.C.D)</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 4: Le Modèle Logique de Données (M.L.D)</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 5: Le Modèle Physique de Données (M.P.D)</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons -->','MERISE','','inherit','closed','closed','','273-revision-v1','','','2026-04-05 12:09:15','2026-04-05 12:09:15','',273,'http://supboost.local/?p=302',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (304,1,'2026-04-05 12:19:40','2026-04-05 12:19:40','<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">Le droit est présent dans tous les aspects de la vie personnelle, professionnelle et sociale. Comprendre les principes fondamentaux du droit permet de mieux connaître ses droits, ses obligations et le fonctionnement des institutions juridiques. Ce cours vous donnera les bases essentielles pour appréhender les différentes branches du droit, comprendre les lois, les contrats et les règles qui régissent la société. Il constitue un socle indispensable pour les études juridiques, la vie professionnelle et la citoyenneté.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">Apprendre le droit, c’est acquérir un outil indispensable pour agir de manière éclairée et responsable dans la vie quotidienne et professionnelle.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 1: le droit objectif</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 2: la règle  de droit</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 3: les sources du droit</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 4: les droits subjectifs</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 5: la classification des droits subjectifs</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 6: la protection des droits subjectifs</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons -->\n\n<!-- wp:paragraph -->\n<p></p>\n<!-- /wp:paragraph -->','Introduction au droit','','inherit','closed','closed','','259-revision-v1','','','2026-04-05 12:19:40','2026-04-05 12:19:40','',259,'http://supboost.local/?p=304',0,'revision','',0);
