INSERT INTO `wp_posts` VALUES (315,1,'2026-04-05 18:10:12','2026-04-05 18:10:12','<!-- wp:heading {\"level\":1} -->\n<h1 class=\"wp-block-heading\">CHAPITRE 1 : INTRODUCTION À MICROSOFT WORD</h1>\n<!-- /wp:heading -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">1. Définition de Microsoft Word</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Microsoft Word est un logiciel de <strong>traitement de texte</strong> développé par Microsoft.<br>Il permet de <strong>saisir, modifier, mettre en forme, enregistrer et imprimer des documents</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Avec Word, on peut créer plusieurs types de documents, par exemple :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>des lettres</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des rapports</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des CV</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des mémoires</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des devoirs</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des tableaux</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des invitations</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des fascicules de cours</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>C’est l’un des logiciels les plus utilisés dans le monde pour les travaux scolaires, universitaires et professionnels.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">2. Importance de Microsoft Word</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Microsoft Word est indispensable car il permet de :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>rédiger des documents propres et bien présentés</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>corriger facilement les erreurs</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>organiser les idées</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>insérer des images et tableaux</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>numéroter les pages</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>créer une table des matières</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>enregistrer les fichiers pour une utilisation future</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>convertir les documents en PDF</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Aujourd’hui, maîtriser Word est une compétence essentielle pour tout étudiant.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">3. Lancement de Microsoft Word</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pour ouvrir Microsoft Word :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Cliquer sur le <strong>menu Démarrer</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Rechercher <strong>Word</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur l’icône du logiciel</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Après ouverture, Word propose généralement :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Document vierge</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>différents <strong>modèles prêts à l’emploi</strong> (CV, lettre, rapport, etc.)</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">4. Présentation de l’interface de Word</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>L’interface de Word comprend plusieurs parties importantes.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:image -->\n<figure class=\"wp-block-image\"><img src=\"https://www.trainingperformance.com/blog/files/uploads/blank-document.jpg\" alt=\"https://www.trainingperformance.com/blog/files/uploads/blank-document.jpg\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image -->\n<figure class=\"wp-block-image\"><img src=\"https://img.webnots.com/2025/07/Microsoft-Word-Interface.jpg\" alt=\"https://img.webnots.com/2025/07/Microsoft-Word-Interface.jpg\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image -->\n<figure class=\"wp-block-image\"><img src=\"https://workforce.libretexts.org/%40api/deki/files/12561/Word2007_4.png?revision=1\" alt=\"https://workforce.libretexts.org/%40api/deki/files/12561/Word2007_4.png?revision=1\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">a) La barre de titre</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Elle se trouve en haut de la fenêtre.<br>Elle affiche le <strong>nom du document</strong> ouvert.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemple :<br><strong>Document1 – Word</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">b) Le ruban</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le ruban est la partie la plus importante.<br>Il contient les différents outils de travail.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>On y trouve plusieurs onglets :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Accueil</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Insertion</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Mise en page</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Références</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Révision</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Affichage</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">c) La zone de travail</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>C’est l’espace blanc où l’on saisit le texte.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>C’est là que l’on rédige le document.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">d) La barre d’état</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Elle se trouve en bas de la fenêtre.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Elle affiche :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>le numéro de page</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>le nombre de mots</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>le zoom</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>la langue du document</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">5. Quelques fonctions de base</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Word permet de réaliser plusieurs opérations simples :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Saisir du texte</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>On écrit directement dans la zone blanche.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Corriger</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>On peut supprimer avec la touche <strong>Retour arrière</strong> ou <strong>Suppr</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Copier et coller</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Ctrl + C</strong> : copier</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Ctrl + V</strong> : coller</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Ctrl + X</strong> : couper</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Annuler</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Ctrl + Z</strong> : annuler la dernière action</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">6. Conclusion du chapitre</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Microsoft Word est un outil fondamental pour la rédaction de documents.<br>Sa maîtrise permet à l’étudiant de produire des travaux clairs, bien structurés et professionnels.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Ce premier chapitre constitue la base avant d’aborder les leçons suivantes comme :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>la mise en forme du texte</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>l’insertion d’images</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>les tableaux</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>la pagination</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>la table des matières</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:file {\"id\":314,\"href\":\"http://supboost.local/wp-content/uploads/2026/04/CHAPITRE-1.docx\"} -->\n<div class=\"wp-block-file\"><a id=\"wp-block-file--media-0e859719-719b-4a55-9c4b-aeb68b182b09\" href=\"http://supboost.local/wp-content/uploads/2026/04/CHAPITRE-1.docx\">CHAPITRE 1: Introduction à Word</a><a href=\"http://supboost.local/wp-content/uploads/2026/04/CHAPITRE-1.docx\" class=\"wp-block-file__button wp-element-button\" download aria-describedby=\"wp-block-file--media-0e859719-719b-4a55-9c4b-aeb68b182b09\">Télécharger le fichier</a></div>\n<!-- /wp:file -->','Chapitre 1: introduction à Word','','inherit','closed','closed','','310-revision-v1','','','2026-04-05 18:10:12','2026-04-05 18:10:12','',310,'http://supboost.local/?p=315',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (317,1,'2026-04-05 18:16:55','2026-04-05 18:16:55','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">1. Définition de Microsoft Word</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Microsoft Word est un logiciel de <strong>traitement de texte</strong> développé par Microsoft.<br>Il permet de <strong>saisir, modifier, mettre en forme, enregistrer et imprimer des documents</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Avec Word, on peut créer plusieurs types de documents, par exemple :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>des lettres</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des rapports</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des CV</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des mémoires</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des devoirs</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des tableaux</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des invitations</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des fascicules de cours</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>C’est l’un des logiciels les plus utilisés dans le monde pour les travaux scolaires, universitaires et professionnels.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">2. Importance de Microsoft Word</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Microsoft Word est indispensable car il permet de :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>rédiger des documents propres et bien présentés</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>corriger facilement les erreurs</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>organiser les idées</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>insérer des images et tableaux</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>numéroter les pages</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>créer une table des matières</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>enregistrer les fichiers pour une utilisation future</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>convertir les documents en PDF</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Aujourd’hui, maîtriser Word est une compétence essentielle pour tout étudiant.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">3. Lancement de Microsoft Word</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pour ouvrir Microsoft Word :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Cliquer sur le <strong>menu Démarrer</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Rechercher <strong>Word</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur l’icône du logiciel</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Après ouverture, Word propose généralement :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Document vierge</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>différents <strong>modèles prêts à l’emploi</strong> (CV, lettre, rapport, etc.)</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">4. Présentation de l’interface de Word</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>L’interface de Word comprend plusieurs parties importantes.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:image -->\n<figure class=\"wp-block-image\"><img src=\"https://www.trainingperformance.com/blog/files/uploads/blank-document.jpg\" alt=\"https://www.trainingperformance.com/blog/files/uploads/blank-document.jpg\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image -->\n<figure class=\"wp-block-image\"><img src=\"https://img.webnots.com/2025/07/Microsoft-Word-Interface.jpg\" alt=\"https://img.webnots.com/2025/07/Microsoft-Word-Interface.jpg\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image -->\n<figure class=\"wp-block-image\"><img src=\"https://workforce.libretexts.org/%40api/deki/files/12561/Word2007_4.png?revision=1\" alt=\"https://workforce.libretexts.org/%40api/deki/files/12561/Word2007_4.png?revision=1\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">a) La barre de titre</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Elle se trouve en haut de la fenêtre.<br>Elle affiche le <strong>nom du document</strong> ouvert.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemple :<br><strong>Document1 – Word</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">b) Le ruban</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le ruban est la partie la plus importante.<br>Il contient les différents outils de travail.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>On y trouve plusieurs onglets :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Accueil</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Insertion</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Mise en page</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Références</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Révision</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Affichage</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">c) La zone de travail</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>C’est l’espace blanc où l’on saisit le texte.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>C’est là que l’on rédige le document.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">d) La barre d’état</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Elle se trouve en bas de la fenêtre.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Elle affiche :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>le numéro de page</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>le nombre de mots</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>le zoom</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>la langue du document</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">5. Quelques fonctions de base</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Word permet de réaliser plusieurs opérations simples :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Saisir du texte</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>On écrit directement dans la zone blanche.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Corriger</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>On peut supprimer avec la touche <strong>Retour arrière</strong> ou <strong>Suppr</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Copier et coller</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Ctrl + C</strong> : copier</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Ctrl + V</strong> : coller</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Ctrl + X</strong> : couper</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Annuler</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Ctrl + Z</strong> : annuler la dernière action</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">6. Conclusion</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Microsoft Word est un outil fondamental pour la rédaction de documents.<br>Sa maîtrise permet à l’étudiant de produire des travaux clairs, bien structurés et professionnels.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Ce premier chapitre constitue la base avant d’aborder les leçons suivantes comme :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>la mise en forme du texte</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>l’insertion d’images</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>les tableaux</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>la pagination</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>la table des matières</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:file {\"id\":314,\"href\":\"http://supboost.local/wp-content/uploads/2026/04/CHAPITRE-1.docx\"} -->\n<div class=\"wp-block-file\"><a id=\"wp-block-file--media-0e859719-719b-4a55-9c4b-aeb68b182b09\" href=\"http://supboost.local/wp-content/uploads/2026/04/CHAPITRE-1.docx\">CHAPITRE 1: Introduction à Word</a><a href=\"http://supboost.local/wp-content/uploads/2026/04/CHAPITRE-1.docx\" class=\"wp-block-file__button wp-element-button\" download aria-describedby=\"wp-block-file--media-0e859719-719b-4a55-9c4b-aeb68b182b09\">Télécharger le fichier</a></div>\n<!-- /wp:file -->','Chapitre 1: introduction à Word','','inherit','closed','closed','','310-revision-v1','','','2026-04-05 18:16:55','2026-04-05 18:16:55','',310,'http://supboost.local/?p=317',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (318,1,'2026-04-05 18:20:12','2026-04-05 18:20:12','<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">La maîtrise de Microsoft Word est une compétence essentielle dans le parcours scolaire et professionnel. Ce logiciel permet de rédiger, mettre en forme et présenter des documents de manière claire, soignée et professionnelle. Grâce à ce cours, vous apprendrez à créer des devoirs, exposés, rapports, lettres, CV et fascicules avec une mise en page structurée et attractive. Vous découvrirez également comment utiliser les outils indispensables tels que les titres, tableaux, images, numérotation, en-têtes, pieds de page et la conversion en PDF.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">Maîtriser Word, c’est améliorer la qualité de vos travaux et gagner en efficacité dans la présentation de vos documents.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-1-introduction-a-word/\">Chapitre 1: introduction à Word</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 2: présentation de Microsoft Word</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 3: Saisie et modification de texte</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 4: Mise en forme  de texte</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 5: mise  en page  et mise en forme de paragraphe</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 6: Insertion d\'objets</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 7: création de Tableaux</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 8: En tête et Pied de Page</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 9 : création de Facture Pro format</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 10: Création d\'une lettre et le Publipostage</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons -->','Microsoft Word','','inherit','closed','closed','','267-revision-v1','','','2026-04-05 18:20:12','2026-04-05 18:20:12','',267,'http://supboost.local/?p=318',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (319,1,'2026-04-05 18:40:34','2026-04-05 18:40:34','<!-- wp:paragraph -->\n<p>1. Définition</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>La saisie de texte consiste à <strong>écrire du contenu dans un document Word</strong> à l’aide du clavier.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>La modification de texte consiste à <strong>corriger, supprimer, déplacer ou ajouter du texte</strong> dans un document déjà commencé.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Ce chapitre est fondamental, car la rédaction et la correction du texte sont les bases de tout travail sur Word.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">2. La saisie du texte</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Lorsque l’on ouvre un document Word, on remarque un <strong>curseur clignotant</strong> appelé <strong>point d’insertion</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>C’est à cet endroit que le texte s’écrit.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Il suffit de placer le curseur dans la zone blanche et de commencer à taper au clavier.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">Microsoft Word est un logiciel de traitement de texte.</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:paragraph -->\n<p>Chaque caractère saisi apparaît à l’endroit du curseur.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">3. Les touches importantes pour la saisie</h2>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">a) La touche Entrée</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Elle permet d’aller à la ligne suivante et de commencer un nouveau paragraphe.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">b) La barre d’espace</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Elle permet de laisser un espace entre deux mots.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">c) La touche Majuscule (Shift)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Elle permet d’écrire une lettre en majuscule.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">d) La touche Verr Maj (Caps Lock)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Elle permet d’écrire plusieurs lettres en majuscules.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">e) La touche Tabulation</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Elle sert à créer un retrait au début d’un paragraphe.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">4. La sélection du texte</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Avant de modifier un texte, il faut souvent le <strong>sélectionner</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Pour sélectionner :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>un mot</strong> : double-cliquer dessus</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>une phrase ou un groupe de mots</strong> : cliquer et glisser la souris</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>tout le texte</strong> : <code>Ctrl + A</code></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Le texte sélectionné apparaît généralement en surbrillance.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">5. La suppression du texte</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pour supprimer du texte, on peut utiliser :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">a) Retour arrière (Backspace)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Supprime le caractère situé <strong>à gauche du curseur</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">b) Suppr (Delete)</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Supprime le caractère situé <strong>à droite du curseur</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">c) Suppression d’un bloc de texte</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Sélectionner le texte puis appuyer sur <strong>Suppr</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">6. Copier, couper et coller</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Ces fonctions permettent de modifier le texte rapidement sans le retaper.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">a) Copier</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Permet de reproduire un texte sans supprimer l’original.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Raccourci :</strong> <code>Ctrl + C</code></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">b) Couper</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Permet de déplacer un texte en le supprimant de son emplacement initial.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Raccourci :</strong> <code>Ctrl + X</code></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">c) Coller</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Permet d’insérer le texte copié ou coupé à un autre endroit.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Raccourci :</strong> <code>Ctrl + V</code></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">7. Déplacer du texte</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pour déplacer un texte :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>sélectionner le texte</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>cliquer sur <strong>Couper</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>placer le curseur au nouvel emplacement</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>cliquer sur <strong>Coller</strong></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Le texte change alors de position dans le document.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">8. Corriger les erreurs</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Word permet de corriger facilement les fautes :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>fautes de frappe</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>fautes d’orthographe</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>mots oubliés</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>mots en double</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Les mots mal orthographiés sont souvent soulignés.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Il suffit de faire <strong>clic droit sur le mot</strong> pour voir les suggestions.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">9. Annuler et rétablir une action</h2>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Annuler</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Permet de revenir sur la dernière action.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Raccourci :</strong> <code>Ctrl + Z</code></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Rétablir</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Permet de remettre une action annulée.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Raccourci :</strong> <code>Ctrl + Y</code></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Cette fonction est très utile lorsqu’on fait une erreur.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Conclusion</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>La saisie et la modification de texte constituent les opérations de base dans Microsoft Word.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>La maîtrise de ces fonctions permet à l’utilisateur de rédiger rapidement un document propre, corriger les erreurs et organiser ses idées.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:file {\"id\":325,\"href\":\"http://supboost.local/wp-content/uploads/2026/04/chapitre-2-saisie-et-modification-de-texte.pdf\",\"displayPreview\":false} -->\n<div class=\"wp-block-file\"><a id=\"wp-block-file--media-a2808b72-fa20-465e-9b63-ee0a8866097d\" href=\"http://supboost.local/wp-content/uploads/2026/04/chapitre-2-saisie-et-modification-de-texte.pdf\">chapitre 2: saisie et modification de texte</a><a href=\"http://supboost.local/wp-content/uploads/2026/04/chapitre-2-saisie-et-modification-de-texte.pdf\" class=\"wp-block-file__button wp-element-button\" download aria-describedby=\"wp-block-file--media-a2808b72-fa20-465e-9b63-ee0a8866097d\">Télécharger le fichier PDF</a></div>\n<!-- /wp:file -->','chapitre 2: saisie et modification de  texte','','publish','closed','closed','','chapitre-2-saisie-et-modification-de-texte','','','2026-04-05 18:53:37','2026-04-05 18:53:37','',0,'http://supboost.local/?page_id=319',0,'page','',0);
INSERT INTO `wp_posts` VALUES (320,1,'2026-04-05 18:39:26','2026-04-05 18:39:26','','CHAPITRE 3','','inherit','open','closed','','chapitre-3','','','2026-04-05 18:39:26','2026-04-05 18:39:26','',319,'http://supboost.local/wp-content/uploads/2026/04/CHAPITRE-3.docx',0,'attachment','application/vnd.openxmlformats-officedocument.wordprocessingml.document',0);
