INSERT INTO `wp_posts` VALUES (335,1,'2026-04-05 19:16:18','2026-04-05 19:16:18','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">1. Définition</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>La mise en forme du texte consiste à <strong>modifier l’apparence du texte</strong> afin de le rendre plus clair, plus lisible et plus attrayant.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Elle permet de mettre en valeur les idées importantes dans un document.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Par exemple, on peut :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>changer la police</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>modifier la taille des caractères</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>mettre en gras</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>mettre en italique</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>souligner</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>changer la couleur</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>aligner le texte</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>La mise en forme se fait principalement dans l’onglet <strong>Accueil</strong> du ruban.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">2. Changer la police d’écriture</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>La police correspond au <strong>style des lettres</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemples de polices :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Times New Roman</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Arial</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Calibri</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cambria</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Sélectionner le texte</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Aller dans l’onglet <strong>Accueil</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur la liste des polices</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir la police voulue</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Un titre peut être écrit en <strong>Arial</strong>, tandis que le corps du texte peut être en <strong>Times New Roman</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">3. Modifier la taille du texte</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>La taille détermine la grandeur des lettres.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Elle s’exprime en <strong>points (pt)</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemples :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>12 pt pour le texte courant</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>14 pt ou 16 pt pour les sous-titres</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>18 pt ou plus pour les grands titres</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Sélectionner le texte</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur la zone de taille</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir la valeur souhaitée</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">4. Mettre le texte en gras</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le gras permet de mettre en évidence un mot ou une idée importante.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Microsoft Word est un logiciel de traitement de texte.</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Sélectionner le texte</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur <strong>G</strong></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Raccourci</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><code>Ctrl + B</code></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">5. Mettre le texte en italique</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>L’italique donne une écriture légèrement inclinée.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Il est souvent utilisé pour les citations, les mots étrangers ou les titres d’ouvrages.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><em>Introduction à Word</em></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Sélectionner le texte</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur <strong>I</strong></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Raccourci</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><code>Ctrl + I</code></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">6. Souligner le texte</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le soulignement permet de mettre en valeur certains mots.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>&lt;u&gt;Chapitre important&lt;/u&gt;</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Sélectionner le texte</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur <strong>S</strong></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Raccourci</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><code>Ctrl + U</code></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">7. Changer la couleur du texte</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Cette fonction permet de rendre le document plus attrayant.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemples de couleurs :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>noir</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>bleu</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>rouge</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>vert</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Sélectionner le texte</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur l’icône <strong>Couleur de police</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir la couleur</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Exemple : les titres peuvent être mis en bleu.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">8. Surligner le texte</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le surlignage permet de mettre en évidence un passage important.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>C’est comme utiliser un stabilo sur un cahier.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Sélectionner le texte</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur l’outil <strong>Surlignage</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir la couleur</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">9. Alignement du texte</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>L’alignement permet de choisir la position du texte dans la page.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">a) Alignement à gauche</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le texte commence à gauche.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>C’est l’alignement le plus courant.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">b) Centré</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le texte est placé au milieu.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Utilisé pour les titres.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">c) Alignement à droite</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le texte est placé à droite.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">d) Justifié</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le texte est aligné à gauche et à droite.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Cet alignement donne un aspect professionnel.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">10. Importance de la mise en forme</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Une bonne mise en forme permet :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>d’améliorer la présentation</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>de faciliter la lecture</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>de rendre le document professionnel</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>de mettre en évidence les idées essentielles</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Conclusion</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>La mise en forme du texte est une étape essentielle dans la rédaction d’un document Word.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Elle permet de transformer un simple texte en un document clair, bien organisé et agréable à lire.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:file {\"id\":334,\"href\":\"http://supboost.local/wp-content/uploads/2026/04/chapitre-3-mise-en-forme-du-document.pdf\",\"displayPreview\":false} -->\n<div class=\"wp-block-file\"><a id=\"wp-block-file--media-a2b39732-2466-47d1-9037-7ad0504b4e4e\" href=\"http://supboost.local/wp-content/uploads/2026/04/chapitre-3-mise-en-forme-du-document.pdf\">chapitre 3: mise en forme du document</a><a href=\"http://supboost.local/wp-content/uploads/2026/04/chapitre-3-mise-en-forme-du-document.pdf\" class=\"wp-block-file__button wp-element-button\" download aria-describedby=\"wp-block-file--media-a2b39732-2466-47d1-9037-7ad0504b4e4e\">Télécharger le fichier PDF</a></div>\n<!-- /wp:file -->','Chapitre 3: mise en forme du document','','inherit','closed','closed','','333-revision-v1','','','2026-04-05 19:16:18','2026-04-05 19:16:18','',333,'http://supboost.local/?p=335',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (336,1,'2026-04-05 19:17:38','2026-04-05 19:17:38','<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">La maîtrise de Microsoft Word est une compétence essentielle dans le parcours scolaire et professionnel. Ce logiciel permet de rédiger, mettre en forme et présenter des documents de manière claire, soignée et professionnelle. Grâce à ce cours, vous apprendrez à créer des devoirs, exposés, rapports, lettres, CV et fascicules avec une mise en page structurée et attractive. Vous découvrirez également comment utiliser les outils indispensables tels que les titres, tableaux, images, numérotation, en-têtes, pieds de page et la conversion en PDF.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">Maîtriser Word, c’est améliorer la qualité de vos travaux et gagner en efficacité dans la présentation de vos documents.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-1-introduction-a-word/\">Chapitre 1: introduction à Word</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-2-saisie-et-modification-de-texte/\">Chapitre 2: Saisie et modification de texte</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-3-mise-en-forme-du-document/\">Chapitre 3: Mise en forme de texte</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 4: mise en page et mise en forme de paragraphe</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 5: Insertion d\'objets</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 6: création de Tableaux</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 7: En tête et Pied de Page</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 8: création de Facture Pro format</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 9: Création d\'une lettre et le Publipostage</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons -->','Microsoft Word','','inherit','closed','closed','','267-revision-v1','','','2026-04-05 19:17:38','2026-04-05 19:17:38','',267,'http://supboost.local/?p=336',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (337,1,'2026-04-06 09:59:37','2026-04-06 09:59:37','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">I. La mise en page</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>La <strong>mise en page</strong> correspond à l’organisation générale de la page du document : marges, orientation, taille, colonnes, en-tête, pied de page, etc. Elle se trouve généralement dans l’onglet <strong>Disposition</strong> ou <strong>Mise en page</strong> selon la version de Word.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1) Les marges</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Les <strong>marges</strong> sont les espaces vides autour du texte.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>marge gauche</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>marge droite</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>marge supérieure</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>marge inférieure</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Cliquer sur <strong>Disposition</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur <strong>Marges</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir :<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Normales</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Étroites</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Larges</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Marges personnalisées</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple conseillé pour un fascicule</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Gauche : <strong>2,5 cm</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Droite : <strong>2,5 cm</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Haut : <strong>2,5 cm</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Bas : <strong>2,5 cm</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2) L’orientation de la page</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>L’orientation définit le sens de la page.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Il existe deux types :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Portrait</strong> : page verticale</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Paysage</strong> : page horizontale</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Disposition → Orientation</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Utilisation :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>portrait pour les cours normaux</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>paysage pour les tableaux larges</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3) La taille de la page</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>La taille la plus utilisée est le <strong>format A4</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Disposition → Taille → A4</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">4) Les sauts de page</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le saut de page permet de commencer le texte sur une nouvelle page sans appuyer plusieurs fois sur Entrée.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Insertion → Saut de page</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>ou <strong>Ctrl + Entrée</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Exemple : commencer un nouveau chapitre sur une nouvelle page.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">5) En-tête et pied de page</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Ils permettent d’ajouter :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>le titre du document</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>le nom de l’auteur</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>la date</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>la numérotation des pages</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Insertion → En-tête / Pied de page</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">II. La mise en paragraphe</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>La <strong>mise en paragraphe</strong> concerne la présentation d’un bloc de texte. Elle agit sur l’alignement, l’espacement, les retraits et l’interligne.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1) Alignement du texte</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Word propose <strong>4 alignements</strong> :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Aligné à gauche</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Centré</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Aligné à droite</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Justifié</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Raccourcis</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Ctrl + L</strong> → gauche</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Ctrl + E</strong> → centré</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Ctrl + R</strong> → droite</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Ctrl + J</strong> → justifié</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Conseil</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pour un cours ou un fascicule, utilise surtout <strong>justifié</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2) Retraits</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le retrait permet de décaler le paragraphe par rapport à la marge.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Types :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>retrait à gauche</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>retrait à droite</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>retrait de première ligne</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Exemple :<br>Le début du paragraphe commence légèrement en retrait.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Valeur conseillée :<br><strong>0,75 cm à 1 cm</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3) Interligne</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>L’interligne est l’espace entre les lignes d’un paragraphe.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemples :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>simple : <strong>1,0</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>moyen : <strong>1,15</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>classique : <strong>1,5</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>espacé : <strong>2,0</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Accueil → Paragraphe → Interligne</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Pour un cours, je te conseille <strong>1,15 ou 1,5</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">4) Espacement avant et après</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Cela permet de mettre de l’espace entre les paragraphes.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemple :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Avant : <strong>0 pt</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Après : <strong>6 pt</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Très utile pour séparer les parties sans utiliser plusieurs lignes vides.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">III. Application pratique</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Exemple de bonne présentation pour un cours :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Police : <strong>Times New Roman</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Taille : <strong>12</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Alignement : <strong>justifié</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Interligne : <strong>1,5</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Retrait première ligne : <strong>1 cm</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Marges : <strong>2,5 cm</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|vivid-red\"}}}},\"textColor\":\"vivid-red\"} -->\n<p class=\"has-vivid-red-color has-text-color has-link-color\">Conclusion</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>La mise en page agit sur <strong>la page entière</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>La mise en paragraphe agit sur <strong>le texte et les paragraphes</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Sans ces réglages, un document paraît désordonné.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:file {\"id\":338,\"href\":\"http://supboost.local/wp-content/uploads/2026/04/chapitre-4-mise-en-page-et-mise-en-paragraphe.pdf\",\"displayPreview\":false} -->\n<div class=\"wp-block-file\"><a id=\"wp-block-file--media-e345b266-8c47-4e8f-bbe0-a22457a04e12\" href=\"http://supboost.local/wp-content/uploads/2026/04/chapitre-4-mise-en-page-et-mise-en-paragraphe.pdf\">chapitre  4: mise en page et mise en paragraphe</a><a href=\"http://supboost.local/wp-content/uploads/2026/04/chapitre-4-mise-en-page-et-mise-en-paragraphe.pdf\" class=\"wp-block-file__button wp-element-button\" download aria-describedby=\"wp-block-file--media-e345b266-8c47-4e8f-bbe0-a22457a04e12\">Télécharger le fichier PDF</a></div>\n<!-- /wp:file -->','Chapitre 4: Mise en page et mise en forme de paragraphe','','publish','closed','closed','','chapitre-4-mise-en-page-et-mise-en-forme-de-paragraphe','','','2026-04-06 09:59:38','2026-04-06 09:59:38','',0,'http://supboost.local/?page_id=337',0,'page','',0);
INSERT INTO `wp_posts` VALUES (338,1,'2026-04-06 09:57:28','2026-04-06 09:57:28','','chapitre  4 mise en page et mise en paragraphe','','inherit','open','closed','','chapitre-4-mise-en-page-et-mise-en-paragraphe','','','2026-04-06 09:57:28','2026-04-06 09:57:28','',337,'http://supboost.local/wp-content/uploads/2026/04/chapitre-4-mise-en-page-et-mise-en-paragraphe.pdf',0,'attachment','application/pdf',0);
INSERT INTO `wp_posts` VALUES (339,1,'2026-04-06 09:59:37','2026-04-06 09:59:37','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">I. La mise en page</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>La <strong>mise en page</strong> correspond à l’organisation générale de la page du document : marges, orientation, taille, colonnes, en-tête, pied de page, etc. Elle se trouve généralement dans l’onglet <strong>Disposition</strong> ou <strong>Mise en page</strong> selon la version de Word.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1) Les marges</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Les <strong>marges</strong> sont les espaces vides autour du texte.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>marge gauche</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>marge droite</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>marge supérieure</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>marge inférieure</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Cliquer sur <strong>Disposition</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur <strong>Marges</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir :<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Normales</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Étroites</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Larges</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Marges personnalisées</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple conseillé pour un fascicule</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Gauche : <strong>2,5 cm</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Droite : <strong>2,5 cm</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Haut : <strong>2,5 cm</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Bas : <strong>2,5 cm</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2) L’orientation de la page</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>L’orientation définit le sens de la page.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Il existe deux types :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Portrait</strong> : page verticale</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Paysage</strong> : page horizontale</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Disposition → Orientation</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Utilisation :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>portrait pour les cours normaux</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>paysage pour les tableaux larges</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3) La taille de la page</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>La taille la plus utilisée est le <strong>format A4</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Disposition → Taille → A4</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">4) Les sauts de page</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le saut de page permet de commencer le texte sur une nouvelle page sans appuyer plusieurs fois sur Entrée.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Insertion → Saut de page</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>ou <strong>Ctrl + Entrée</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Exemple : commencer un nouveau chapitre sur une nouvelle page.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">5) En-tête et pied de page</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Ils permettent d’ajouter :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>le titre du document</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>le nom de l’auteur</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>la date</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>la numérotation des pages</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Insertion → En-tête / Pied de page</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">II. La mise en paragraphe</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>La <strong>mise en paragraphe</strong> concerne la présentation d’un bloc de texte. Elle agit sur l’alignement, l’espacement, les retraits et l’interligne.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1) Alignement du texte</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Word propose <strong>4 alignements</strong> :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Aligné à gauche</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Centré</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Aligné à droite</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Justifié</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Raccourcis</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Ctrl + L</strong> → gauche</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Ctrl + E</strong> → centré</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Ctrl + R</strong> → droite</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Ctrl + J</strong> → justifié</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Conseil</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pour un cours ou un fascicule, utilise surtout <strong>justifié</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2) Retraits</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le retrait permet de décaler le paragraphe par rapport à la marge.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Types :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>retrait à gauche</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>retrait à droite</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>retrait de première ligne</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Exemple :<br>Le début du paragraphe commence légèrement en retrait.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Valeur conseillée :<br><strong>0,75 cm à 1 cm</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3) Interligne</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>L’interligne est l’espace entre les lignes d’un paragraphe.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemples :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>simple : <strong>1,0</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>moyen : <strong>1,15</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>classique : <strong>1,5</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>espacé : <strong>2,0</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Accueil → Paragraphe → Interligne</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Pour un cours, je te conseille <strong>1,15 ou 1,5</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">4) Espacement avant et après</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Cela permet de mettre de l’espace entre les paragraphes.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemple :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Avant : <strong>0 pt</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Après : <strong>6 pt</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Très utile pour séparer les parties sans utiliser plusieurs lignes vides.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">III. Application pratique</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Exemple de bonne présentation pour un cours :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Police : <strong>Times New Roman</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Taille : <strong>12</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Alignement : <strong>justifié</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Interligne : <strong>1,5</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Retrait première ligne : <strong>1 cm</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Marges : <strong>2,5 cm</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|vivid-red\"}}}},\"textColor\":\"vivid-red\"} -->\n<p class=\"has-vivid-red-color has-text-color has-link-color\">Conclusion</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>La mise en page agit sur <strong>la page entière</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>La mise en paragraphe agit sur <strong>le texte et les paragraphes</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Sans ces réglages, un document paraît désordonné.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:file {\"id\":338,\"href\":\"http://supboost.local/wp-content/uploads/2026/04/chapitre-4-mise-en-page-et-mise-en-paragraphe.pdf\",\"displayPreview\":false} -->\n<div class=\"wp-block-file\"><a id=\"wp-block-file--media-e345b266-8c47-4e8f-bbe0-a22457a04e12\" href=\"http://supboost.local/wp-content/uploads/2026/04/chapitre-4-mise-en-page-et-mise-en-paragraphe.pdf\">chapitre  4: mise en page et mise en paragraphe</a><a href=\"http://supboost.local/wp-content/uploads/2026/04/chapitre-4-mise-en-page-et-mise-en-paragraphe.pdf\" class=\"wp-block-file__button wp-element-button\" download aria-describedby=\"wp-block-file--media-e345b266-8c47-4e8f-bbe0-a22457a04e12\">Télécharger le fichier PDF</a></div>\n<!-- /wp:file -->','Chapitre 4: Mise en page et mise en forme de paragraphe','','inherit','closed','closed','','337-revision-v1','','','2026-04-06 09:59:37','2026-04-06 09:59:37','',337,'http://supboost.local/?p=339',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (340,1,'2026-04-06 10:01:35','2026-04-06 10:01:35','<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">La maîtrise de Microsoft Word est une compétence essentielle dans le parcours scolaire et professionnel. Ce logiciel permet de rédiger, mettre en forme et présenter des documents de manière claire, soignée et professionnelle. Grâce à ce cours, vous apprendrez à créer des devoirs, exposés, rapports, lettres, CV et fascicules avec une mise en page structurée et attractive. Vous découvrirez également comment utiliser les outils indispensables tels que les titres, tableaux, images, numérotation, en-têtes, pieds de page et la conversion en PDF.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">Maîtriser Word, c’est améliorer la qualité de vos travaux et gagner en efficacité dans la présentation de vos documents.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-1-introduction-a-word/\">Chapitre 1: introduction à Word</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-2-saisie-et-modification-de-texte/\">Chapitre 2: Saisie et modification de texte</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-3-mise-en-forme-du-document/\">Chapitre 3: Mise en forme de texte</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-4-mise-en-page-et-mise-en-forme-de-paragraphe/\">Chapitre 4: mise en page et mise en forme de paragraphe</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 5: Insertion d\'objets</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 6: création de Tableaux</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 7: En tête et Pied de Page</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 8: création de Facture Pro format</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 9: Création d\'une lettre et le Publipostage</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons -->','Microsoft Word','','inherit','closed','closed','','267-revision-v1','','','2026-04-06 10:01:35','2026-04-06 10:01:35','',267,'http://supboost.local/?p=340',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (341,1,'2026-04-06 10:12:41','2026-04-06 10:12:41','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">I. Définition</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>L’<strong>insertion d’objet</strong> consiste à ajouter dans un document Word des éléments autres que du simple texte.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Ces objets peuvent être :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>des <strong>images</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des <strong>tableaux</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des <strong>formes</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des <strong>zones de texte</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des <strong>WordArt</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des <strong>symboles</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des <strong>graphiques</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des <strong>fichiers PDF ou Excel</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des <strong>SmartArt</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Tous ces éléments se trouvent dans l’onglet <strong>Insertion</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">II. Insertion d’une image</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>L’image permet d’illustrer le texte et de mieux faire comprendre une idée.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Cliquer sur <strong>Insertion</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur <strong>Images</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir l’image dans l’ordinateur</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur <strong>Insérer</strong></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Insérer le logo de l’école ou une photo dans un rapport.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">III. Insertion d’un tableau</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le tableau sert à organiser les informations en <strong>lignes et colonnes</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Insertion → Tableau</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir le nombre de lignes et de colonnes</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Valider</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><th>Nom</th><th>Classe</th><th>Moyenne</th></tr></thead><tbody><tr><td>Aliou</td><td>Terminale</td><td>15</td></tr><tr><td>Fatou</td><td>Première</td><td>14</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">IV. Insertion de formes</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Les formes permettent d’ajouter :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>carrés</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>rectangles</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>flèches</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>cercles</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>lignes</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Insertion → Formes</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir la forme</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Dessiner sur la page</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Utilité</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Très utile pour les schémas, organigrammes et exercices.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">V. Insertion d’une zone de texte</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>La zone de texte permet d’écrire un texte dans un cadre indépendant.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Insertion → Zone de texte</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir un modèle</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Saisir le texte</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Mettre une citation, une remarque ou un résumé.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VI. Insertion de WordArt</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le WordArt permet de styliser un titre.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Insertion → WordArt</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir un style</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Écrire le texte</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Titre : <strong>Chapitre 5 – Insertion d’objet</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VII. Insertion de symboles</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Les symboles servent à insérer des caractères spéciaux.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemples :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>€</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>©</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>™</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>α</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>β</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>√</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Insertion → Symbole</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VIII. Insertion d’un objet fichier</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Word permet aussi d’insérer un fichier existant comme un <strong>PDF, un document Excel ou PowerPoint</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Insertion → Objet</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir <strong>Créer à partir d’un fichier</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Parcourir et sélectionner le fichier</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur <strong>OK</strong></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Insérer un tableau Excel dans un rapport Word.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">IX. SmartArt</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le SmartArt permet de créer des schémas visuels.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemples :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>hiérarchie</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>organigramme</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>cycle</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>pyramide</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Insertion → SmartArt</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir le modèle</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Saisir les informations</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Conclusion</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>L’insertion d’objet permet d’enrichir un document avec des éléments visuels et informatifs.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Un bon document Word ne contient pas seulement du texte, mais aussi :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>images</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>tableaux</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>schémas</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>fichiers</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>titres décorés</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Cela améliore fortement la présentation.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:file {\"id\":342,\"href\":\"http://supboost.local/wp-content/uploads/2026/04/Chapitre-5-insertion-dobjets.pdf\",\"displayPreview\":false} -->\n<div class=\"wp-block-file\"><a id=\"wp-block-file--media-4bf03f5e-df48-44fc-b1ef-68d758e276aa\" href=\"http://supboost.local/wp-content/uploads/2026/04/Chapitre-5-insertion-dobjets.pdf\">Chapitre 5: insertion d\'objets</a><a href=\"http://supboost.local/wp-content/uploads/2026/04/Chapitre-5-insertion-dobjets.pdf\" class=\"wp-block-file__button wp-element-button\" download aria-describedby=\"wp-block-file--media-4bf03f5e-df48-44fc-b1ef-68d758e276aa\">Télécharger le fichier PDF</a></div>\n<!-- /wp:file -->','Chapitre 5: insertion d\'objet','','publish','closed','closed','','chapitre-5-insertion-dobjet','','','2026-04-06 10:12:41','2026-04-06 10:12:41','',0,'http://supboost.local/?page_id=341',0,'page','',0);
