INSERT INTO `wp_posts` VALUES (343,1,'2026-04-06 10:12:41','2026-04-06 10:12:41','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">I. Définition</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>L’<strong>insertion d’objet</strong> consiste à ajouter dans un document Word des éléments autres que du simple texte.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Ces objets peuvent être :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>des <strong>images</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des <strong>tableaux</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des <strong>formes</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des <strong>zones de texte</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des <strong>WordArt</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des <strong>symboles</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des <strong>graphiques</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des <strong>fichiers PDF ou Excel</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des <strong>SmartArt</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Tous ces éléments se trouvent dans l’onglet <strong>Insertion</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">II. Insertion d’une image</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>L’image permet d’illustrer le texte et de mieux faire comprendre une idée.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Cliquer sur <strong>Insertion</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur <strong>Images</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir l’image dans l’ordinateur</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur <strong>Insérer</strong></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Insérer le logo de l’école ou une photo dans un rapport.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">III. Insertion d’un tableau</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le tableau sert à organiser les informations en <strong>lignes et colonnes</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Insertion → Tableau</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir le nombre de lignes et de colonnes</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Valider</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><th>Nom</th><th>Classe</th><th>Moyenne</th></tr></thead><tbody><tr><td>Aliou</td><td>Terminale</td><td>15</td></tr><tr><td>Fatou</td><td>Première</td><td>14</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">IV. Insertion de formes</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Les formes permettent d’ajouter :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>carrés</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>rectangles</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>flèches</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>cercles</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>lignes</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Insertion → Formes</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir la forme</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Dessiner sur la page</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Utilité</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Très utile pour les schémas, organigrammes et exercices.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">V. Insertion d’une zone de texte</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>La zone de texte permet d’écrire un texte dans un cadre indépendant.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Insertion → Zone de texte</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir un modèle</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Saisir le texte</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Mettre une citation, une remarque ou un résumé.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VI. Insertion de WordArt</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le WordArt permet de styliser un titre.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Insertion → WordArt</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir un style</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Écrire le texte</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Titre : <strong>Chapitre 5 – Insertion d’objet</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VII. Insertion de symboles</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Les symboles servent à insérer des caractères spéciaux.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemples :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>€</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>©</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>™</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>α</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>β</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>√</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Insertion → Symbole</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VIII. Insertion d’un objet fichier</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Word permet aussi d’insérer un fichier existant comme un <strong>PDF, un document Excel ou PowerPoint</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Insertion → Objet</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir <strong>Créer à partir d’un fichier</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Parcourir et sélectionner le fichier</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur <strong>OK</strong></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Insérer un tableau Excel dans un rapport Word.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">IX. SmartArt</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le SmartArt permet de créer des schémas visuels.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemples :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>hiérarchie</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>organigramme</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>cycle</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>pyramide</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Insertion → SmartArt</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir le modèle</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Saisir les informations</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Conclusion</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>L’insertion d’objet permet d’enrichir un document avec des éléments visuels et informatifs.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Un bon document Word ne contient pas seulement du texte, mais aussi :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>images</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>tableaux</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>schémas</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>fichiers</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>titres décorés</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Cela améliore fortement la présentation.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:file {\"id\":342,\"href\":\"http://supboost.local/wp-content/uploads/2026/04/Chapitre-5-insertion-dobjets.pdf\",\"displayPreview\":false} -->\n<div class=\"wp-block-file\"><a id=\"wp-block-file--media-4bf03f5e-df48-44fc-b1ef-68d758e276aa\" href=\"http://supboost.local/wp-content/uploads/2026/04/Chapitre-5-insertion-dobjets.pdf\">Chapitre 5: insertion d\'objets</a><a href=\"http://supboost.local/wp-content/uploads/2026/04/Chapitre-5-insertion-dobjets.pdf\" class=\"wp-block-file__button wp-element-button\" download aria-describedby=\"wp-block-file--media-4bf03f5e-df48-44fc-b1ef-68d758e276aa\">Télécharger le fichier PDF</a></div>\n<!-- /wp:file -->','Chapitre 5: insertion d\'objet','','inherit','closed','closed','','341-revision-v1','','','2026-04-06 10:12:41','2026-04-06 10:12:41','',341,'http://supboost.local/?p=343',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (344,1,'2026-04-06 10:13:37','2026-04-06 10:13:37','<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">La maîtrise de Microsoft Word est une compétence essentielle dans le parcours scolaire et professionnel. Ce logiciel permet de rédiger, mettre en forme et présenter des documents de manière claire, soignée et professionnelle. Grâce à ce cours, vous apprendrez à créer des devoirs, exposés, rapports, lettres, CV et fascicules avec une mise en page structurée et attractive. Vous découvrirez également comment utiliser les outils indispensables tels que les titres, tableaux, images, numérotation, en-têtes, pieds de page et la conversion en PDF.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">Maîtriser Word, c’est améliorer la qualité de vos travaux et gagner en efficacité dans la présentation de vos documents.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-1-introduction-a-word/\">Chapitre 1: introduction à Word</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-2-saisie-et-modification-de-texte/\">Chapitre 2: Saisie et modification de texte</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-3-mise-en-forme-du-document/\">Chapitre 3: Mise en forme de texte</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-4-mise-en-page-et-mise-en-forme-de-paragraphe/\">Chapitre 4: mise en page et mise en forme de paragraphe</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-5-insertion-dobjet/\">Chapitre 5: Insertion d\'objets</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 6: création de Tableaux</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 7: En tête et Pied de Page</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 8: création de Facture Pro format</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 9: Création d\'une lettre et le Publipostage</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons -->','Microsoft Word','','inherit','closed','closed','','267-revision-v1','','','2026-04-06 10:13:37','2026-04-06 10:13:37','',267,'http://supboost.local/?p=344',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (345,1,'2026-04-06 10:25:29','2026-04-06 10:25:29','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">I. Définition</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Un <strong>tableau</strong> est un ensemble de <strong>lignes</strong> et de <strong>colonnes</strong> qui se croisent pour former des <strong>cellules</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Chaque cellule peut contenir :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>du texte</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des nombres</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des dates</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des images</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Le tableau permet de présenter les données de manière ordonnée.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><th>Nom</th><th>Classe</th><th>Moyenne</th></tr></thead><tbody><tr><td>Awa</td><td>Terminale</td><td>15</td></tr><tr><td>Moussa</td><td>Première</td><td>14</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">II. Importance du tableau</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le tableau permet de :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>classer les informations</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>faciliter la lecture</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>comparer des données</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>rendre un document plus professionnel</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Exemple : liste des élèves, emploi du temps, relevé de notes.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">III. Création d’un tableau</h2>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Méthode 1 : création rapide</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Cliquer sur <strong>Insertion</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur <strong>Tableau</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Faire glisser la souris sur la grille</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir le nombre de <strong>lignes</strong> et <strong>colonnes</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer pour valider</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pour un tableau de 3 colonnes et 4 lignes, sélectionner <strong>3 × 4</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">IV. Saisie dans le tableau</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pour écrire dans une cellule :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Cliquer dans la cellule</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Saisir le texte</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Pour passer à la cellule suivante, utiliser la touche <strong>Tabulation (Tab)</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">V. Ajouter des lignes et colonnes</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Il arrive qu’on veuille agrandir le tableau.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Ajouter une ligne</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Cliquer dans le tableau</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Aller sur <strong>Disposition</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur <strong>Insérer au-dessus</strong> ou <strong>Insérer en dessous</strong></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Ajouter une colonne</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Cliquer dans le tableau</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Disposition</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Insérer à gauche</strong> ou <strong>Insérer à droite</strong></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VI. Supprimer des lignes ou colonnes</h2>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Sélectionner la ligne ou la colonne</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur <strong>Disposition</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir <strong>Supprimer</strong></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>On peut supprimer :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>une ligne</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>une colonne</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>tout le tableau</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VII. Fusionner les cellules</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Fusionner signifie <strong>réunir plusieurs cellules en une seule</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Sélectionner les cellules</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Disposition → Fusionner les cellules</strong></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Très utile pour créer un grand titre au-dessus du tableau.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VIII. Mise en forme du tableau</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Word permet de modifier l’apparence du tableau.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>On peut changer :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>la couleur</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>les bordures</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>l’épaisseur des traits</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>l’alignement du texte</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>le style du tableau</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Cliquer sur le tableau puis aller dans <strong>Création de tableau</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">IX. Ajuster la taille</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>On peut modifier :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>la largeur des colonnes</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>la hauteur des lignes</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Il suffit de <strong>faire glisser les bordures</strong> avec la souris.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">X. Exemple pratique</h2>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Tableau des notes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><th>Matière</th><th>Note</th></tr></thead><tbody><tr><td>Mathématiques</td><td>16</td></tr><tr><td>Histoire</td><td>14</td></tr><tr><td>Français</td><td>15</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Conclusion</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Un tableau est composé de :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>lignes</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>colonnes</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>cellules</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Il sert à mieux organiser les informations.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>C’est une compétence très importante en bureautique.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:file {\"id\":346,\"href\":\"http://supboost.local/wp-content/uploads/2026/04/Chapitre-6-creation-de-tableaux.pdf\",\"displayPreview\":false} -->\n<div class=\"wp-block-file\"><a id=\"wp-block-file--media-8a4aa960-abdb-4fd9-be86-1145fe5a9ac8\" href=\"http://supboost.local/wp-content/uploads/2026/04/Chapitre-6-creation-de-tableaux.pdf\">Chapitre 6:  création de tableaux</a><a href=\"http://supboost.local/wp-content/uploads/2026/04/Chapitre-6-creation-de-tableaux.pdf\" class=\"wp-block-file__button wp-element-button\" download aria-describedby=\"wp-block-file--media-8a4aa960-abdb-4fd9-be86-1145fe5a9ac8\">Télécharger le fichier PDF</a></div>\n<!-- /wp:file -->','Chapitre 6: création de tableux','','publish','closed','closed','','chapitre-6-creation-de-tableux','','','2026-04-06 10:25:29','2026-04-06 10:25:29','',0,'http://supboost.local/?page_id=345',0,'page','',0);
