INSERT INTO `wp_posts` VALUES (347,1,'2026-04-06 10:25:29','2026-04-06 10:25:29','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">I. Définition</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Un <strong>tableau</strong> est un ensemble de <strong>lignes</strong> et de <strong>colonnes</strong> qui se croisent pour former des <strong>cellules</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Chaque cellule peut contenir :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>du texte</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des nombres</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des dates</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>des images</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Le tableau permet de présenter les données de manière ordonnée.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><th>Nom</th><th>Classe</th><th>Moyenne</th></tr></thead><tbody><tr><td>Awa</td><td>Terminale</td><td>15</td></tr><tr><td>Moussa</td><td>Première</td><td>14</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">II. Importance du tableau</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le tableau permet de :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>classer les informations</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>faciliter la lecture</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>comparer des données</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>rendre un document plus professionnel</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Exemple : liste des élèves, emploi du temps, relevé de notes.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">III. Création d’un tableau</h2>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Méthode 1 : création rapide</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Cliquer sur <strong>Insertion</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur <strong>Tableau</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Faire glisser la souris sur la grille</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir le nombre de <strong>lignes</strong> et <strong>colonnes</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer pour valider</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pour un tableau de 3 colonnes et 4 lignes, sélectionner <strong>3 × 4</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">IV. Saisie dans le tableau</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pour écrire dans une cellule :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Cliquer dans la cellule</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Saisir le texte</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Pour passer à la cellule suivante, utiliser la touche <strong>Tabulation (Tab)</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">V. Ajouter des lignes et colonnes</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Il arrive qu’on veuille agrandir le tableau.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Ajouter une ligne</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Cliquer dans le tableau</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Aller sur <strong>Disposition</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur <strong>Insérer au-dessus</strong> ou <strong>Insérer en dessous</strong></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Ajouter une colonne</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Cliquer dans le tableau</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Disposition</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Insérer à gauche</strong> ou <strong>Insérer à droite</strong></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VI. Supprimer des lignes ou colonnes</h2>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Sélectionner la ligne ou la colonne</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur <strong>Disposition</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir <strong>Supprimer</strong></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>On peut supprimer :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>une ligne</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>une colonne</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>tout le tableau</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VII. Fusionner les cellules</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Fusionner signifie <strong>réunir plusieurs cellules en une seule</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Sélectionner les cellules</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Disposition → Fusionner les cellules</strong></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Très utile pour créer un grand titre au-dessus du tableau.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VIII. Mise en forme du tableau</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Word permet de modifier l’apparence du tableau.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>On peut changer :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>la couleur</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>les bordures</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>l’épaisseur des traits</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>l’alignement du texte</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>le style du tableau</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Cliquer sur le tableau puis aller dans <strong>Création de tableau</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">IX. Ajuster la taille</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>On peut modifier :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>la largeur des colonnes</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>la hauteur des lignes</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Il suffit de <strong>faire glisser les bordures</strong> avec la souris.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">X. Exemple pratique</h2>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Tableau des notes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><th>Matière</th><th>Note</th></tr></thead><tbody><tr><td>Mathématiques</td><td>16</td></tr><tr><td>Histoire</td><td>14</td></tr><tr><td>Français</td><td>15</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Conclusion</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Un tableau est composé de :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>lignes</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>colonnes</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>cellules</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Il sert à mieux organiser les informations.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>C’est une compétence très importante en bureautique.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:file {\"id\":346,\"href\":\"http://supboost.local/wp-content/uploads/2026/04/Chapitre-6-creation-de-tableaux.pdf\",\"displayPreview\":false} -->\n<div class=\"wp-block-file\"><a id=\"wp-block-file--media-8a4aa960-abdb-4fd9-be86-1145fe5a9ac8\" href=\"http://supboost.local/wp-content/uploads/2026/04/Chapitre-6-creation-de-tableaux.pdf\">Chapitre 6:  création de tableaux</a><a href=\"http://supboost.local/wp-content/uploads/2026/04/Chapitre-6-creation-de-tableaux.pdf\" class=\"wp-block-file__button wp-element-button\" download aria-describedby=\"wp-block-file--media-8a4aa960-abdb-4fd9-be86-1145fe5a9ac8\">Télécharger le fichier PDF</a></div>\n<!-- /wp:file -->','Chapitre 6: création de tableux','','inherit','closed','closed','','345-revision-v1','','','2026-04-06 10:25:29','2026-04-06 10:25:29','',345,'http://supboost.local/?p=347',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (348,1,'2026-04-06 10:26:53','2026-04-06 10:26:53','<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">La maîtrise de Microsoft Word est une compétence essentielle dans le parcours scolaire et professionnel. Ce logiciel permet de rédiger, mettre en forme et présenter des documents de manière claire, soignée et professionnelle. Grâce à ce cours, vous apprendrez à créer des devoirs, exposés, rapports, lettres, CV et fascicules avec une mise en page structurée et attractive. Vous découvrirez également comment utiliser les outils indispensables tels que les titres, tableaux, images, numérotation, en-têtes, pieds de page et la conversion en PDF.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">Maîtriser Word, c’est améliorer la qualité de vos travaux et gagner en efficacité dans la présentation de vos documents.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-1-introduction-a-word/\">Chapitre 1: introduction à Word</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-2-saisie-et-modification-de-texte/\">Chapitre 2: Saisie et modification de texte</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-3-mise-en-forme-du-document/\">Chapitre 3: Mise en forme de texte</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-4-mise-en-page-et-mise-en-forme-de-paragraphe/\">Chapitre 4: mise en page et mise en forme de paragraphe</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-5-insertion-dobjet/\">Chapitre 5: Insertion d\'objets</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-6-creation-de-tableux/\">Chapitre 6: création de Tableaux</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 7: En tête et Pied de Page</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 8: création de Facture Pro format</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 9: Création d\'une lettre et le Publipostage</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons -->','Microsoft Word','','inherit','closed','closed','','267-revision-v1','','','2026-04-06 10:26:53','2026-04-06 10:26:53','',267,'http://supboost.local/?p=348',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (349,1,'2026-04-06 10:36:44','2026-04-06 10:36:44','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">I. Définition</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>L’<strong>en-tête</strong> est la partie située en <strong>haut de chaque page</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Le <strong>pied de page</strong> est la partie située en <strong>bas de chaque page</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Ces zones permettent d’afficher des informations répétées sur toutes les pages du document.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemples d’informations</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>le titre du document</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>le nom de l’auteur</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>la classe</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>la date</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>le numéro de page</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">II. Importance</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>L’en-tête et le pied de page servent à :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>identifier le document</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>faciliter la lecture</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>numéroter les pages</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>améliorer la présentation</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Ils sont très utilisés dans :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>les mémoires</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>les rapports</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>les fascicules</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>les devoirs</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">III. Insertion d’un en-tête</h2>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Cliquer sur <strong>Insertion</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur <strong>En-tête</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir un modèle</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Saisir le texte souhaité</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Cours de bureautique – Microsoft Word</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:image -->\n<figure class=\"wp-block-image\"><img src=\"https://www.sitesbay.com/word/images/inseert-header-and-footer-in-word1.png\" alt=\"https://www.sitesbay.com/word/images/inseert-header-and-footer-in-word1.png\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image -->\n<figure class=\"wp-block-image\"><img src=\"https://i0.wp.com/support.content.office.net/fr-fr/media/7a88a62c-794c-4786-9fc1-c0237c28aa03.png?ssl=1&amp;w=720\" alt=\"https://i0.wp.com/support.content.office.net/fr-fr/media/7a88a62c-794c-4786-9fc1-c0237c28aa03.png?ssl=1&amp;w=720\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">IV. Insertion d’un pied de page</h2>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Cliquer sur <strong>Insertion</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur <strong>Pied de page</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir un modèle</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Écrire le texte voulu</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Page 1</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">V. Numérotation des pages</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le plus souvent, le numéro de page se place dans le pied de page.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Insertion → Numéro de page</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir :<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>haut de page</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>bas de page</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>position actuelle</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Page 1, Page 2, Page 3…</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VI. Modifier l’en-tête ou le pied de page</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pour modifier un texte déjà mis :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>double-cliquer sur la zone en haut ou en bas de la page</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>apporter les modifications</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>cliquer sur <strong>Fermer l’en-tête et le pied de page</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VII. Première page différente</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Word permet de mettre une première page sans en-tête ni pied de page.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Cette option est très utile pour la <strong>page de garde</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Double-cliquer dans l’en-tête</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cocher <strong>Première page différente</strong></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Exemple :<br>la page de garde n’a pas de numéro, mais les autres pages oui.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VIII. En-têtes différents selon les sections</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Dans un long document, chaque partie peut avoir son propre en-tête.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemple :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Partie I : Histoire</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Partie II : Géographie</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Mise en page → Saut de page</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Créer une nouvelle section</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Désactiver <strong>Lier au précédent</strong></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">IX. Exemple pratique</h2>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">En-tête</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Fascicule de bureautique</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Pied de page</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Page 1</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>C’est le modèle idéal pour un cours ou un fascicule.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">conclusion</h2>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>l’en-tête = haut de page</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>le pied de page = bas de page</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>ils servent à répéter des informations sur toutes les pages</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>ils rendent le document plus professionnel</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:file {\"id\":350,\"href\":\"http://supboost.local/wp-content/uploads/2026/04/Chapitre-7-en-tete-et-pied-de-page.pdf\",\"displayPreview\":false} -->\n<div class=\"wp-block-file\"><a id=\"wp-block-file--media-ad64824c-4781-4d6c-853d-29343826fbd1\" href=\"http://supboost.local/wp-content/uploads/2026/04/Chapitre-7-en-tete-et-pied-de-page.pdf\">Chapitre 7:  en tête et pied de page</a><a href=\"http://supboost.local/wp-content/uploads/2026/04/Chapitre-7-en-tete-et-pied-de-page.pdf\" class=\"wp-block-file__button wp-element-button\" download aria-describedby=\"wp-block-file--media-ad64824c-4781-4d6c-853d-29343826fbd1\">Télécharger le fichier PDF</a></div>\n<!-- /wp:file -->','Chapitre 7: En- tête et Pied de page','','publish','closed','closed','','chapitre-7-en-tete-et-pied-de-page','','','2026-04-06 10:36:44','2026-04-06 10:36:44','',0,'http://supboost.local/?page_id=349',0,'page','',0);
INSERT INTO `wp_posts` VALUES (350,1,'2026-04-06 10:35:20','2026-04-06 10:35:20','','Chapitre 7 en tête et pied de page','','inherit','open','closed','','chapitre-7-en-tete-et-pied-de-page','','','2026-04-06 10:35:20','2026-04-06 10:35:20','',349,'http://supboost.local/wp-content/uploads/2026/04/Chapitre-7-en-tete-et-pied-de-page.pdf',0,'attachment','application/pdf',0);
INSERT INTO `wp_posts` VALUES (351,1,'2026-04-06 10:36:44','2026-04-06 10:36:44','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">I. Définition</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>L’<strong>en-tête</strong> est la partie située en <strong>haut de chaque page</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Le <strong>pied de page</strong> est la partie située en <strong>bas de chaque page</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Ces zones permettent d’afficher des informations répétées sur toutes les pages du document.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemples d’informations</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>le titre du document</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>le nom de l’auteur</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>la classe</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>la date</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>le numéro de page</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">II. Importance</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>L’en-tête et le pied de page servent à :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>identifier le document</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>faciliter la lecture</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>numéroter les pages</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>améliorer la présentation</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Ils sont très utilisés dans :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>les mémoires</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>les rapports</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>les fascicules</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>les devoirs</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">III. Insertion d’un en-tête</h2>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Cliquer sur <strong>Insertion</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur <strong>En-tête</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir un modèle</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Saisir le texte souhaité</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Cours de bureautique – Microsoft Word</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:image -->\n<figure class=\"wp-block-image\"><img src=\"https://www.sitesbay.com/word/images/inseert-header-and-footer-in-word1.png\" alt=\"https://www.sitesbay.com/word/images/inseert-header-and-footer-in-word1.png\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:image -->\n<figure class=\"wp-block-image\"><img src=\"https://i0.wp.com/support.content.office.net/fr-fr/media/7a88a62c-794c-4786-9fc1-c0237c28aa03.png?ssl=1&amp;w=720\" alt=\"https://i0.wp.com/support.content.office.net/fr-fr/media/7a88a62c-794c-4786-9fc1-c0237c28aa03.png?ssl=1&amp;w=720\"/></figure>\n<!-- /wp:image -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">IV. Insertion d’un pied de page</h2>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Cliquer sur <strong>Insertion</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur <strong>Pied de page</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir un modèle</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Écrire le texte voulu</li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Page 1</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">V. Numérotation des pages</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le plus souvent, le numéro de page se place dans le pied de page.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Insertion → Numéro de page</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Choisir :<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>haut de page</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>bas de page</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>position actuelle</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list --></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Page 1, Page 2, Page 3…</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VI. Modifier l’en-tête ou le pied de page</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pour modifier un texte déjà mis :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>double-cliquer sur la zone en haut ou en bas de la page</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>apporter les modifications</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>cliquer sur <strong>Fermer l’en-tête et le pied de page</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VII. Première page différente</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Word permet de mettre une première page sans en-tête ni pied de page.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Cette option est très utile pour la <strong>page de garde</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Double-cliquer dans l’en-tête</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cocher <strong>Première page différente</strong></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Exemple :<br>la page de garde n’a pas de numéro, mais les autres pages oui.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VIII. En-têtes différents selon les sections</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Dans un long document, chaque partie peut avoir son propre en-tête.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemple :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Partie I : Histoire</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Partie II : Géographie</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Étapes</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list {\"ordered\":true} -->\n<ol class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Mise en page → Saut de page</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Créer une nouvelle section</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Désactiver <strong>Lier au précédent</strong></li>\n<!-- /wp:list-item --></ol>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">IX. Exemple pratique</h2>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">En-tête</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Fascicule de bureautique</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Pied de page</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Page 1</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>C’est le modèle idéal pour un cours ou un fascicule.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">conclusion</h2>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>l’en-tête = haut de page</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>le pied de page = bas de page</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>ils servent à répéter des informations sur toutes les pages</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>ils rendent le document plus professionnel</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:file {\"id\":350,\"href\":\"http://supboost.local/wp-content/uploads/2026/04/Chapitre-7-en-tete-et-pied-de-page.pdf\",\"displayPreview\":false} -->\n<div class=\"wp-block-file\"><a id=\"wp-block-file--media-ad64824c-4781-4d6c-853d-29343826fbd1\" href=\"http://supboost.local/wp-content/uploads/2026/04/Chapitre-7-en-tete-et-pied-de-page.pdf\">Chapitre 7:  en tête et pied de page</a><a href=\"http://supboost.local/wp-content/uploads/2026/04/Chapitre-7-en-tete-et-pied-de-page.pdf\" class=\"wp-block-file__button wp-element-button\" download aria-describedby=\"wp-block-file--media-ad64824c-4781-4d6c-853d-29343826fbd1\">Télécharger le fichier PDF</a></div>\n<!-- /wp:file -->','Chapitre 7: En- tête et Pied de page','','inherit','closed','closed','','349-revision-v1','','','2026-04-06 10:36:44','2026-04-06 10:36:44','',349,'http://supboost.local/?p=351',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (352,1,'2026-04-06 10:37:42','2026-04-06 10:37:42','<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">La maîtrise de Microsoft Word est une compétence essentielle dans le parcours scolaire et professionnel. Ce logiciel permet de rédiger, mettre en forme et présenter des documents de manière claire, soignée et professionnelle. Grâce à ce cours, vous apprendrez à créer des devoirs, exposés, rapports, lettres, CV et fascicules avec une mise en page structurée et attractive. Vous découvrirez également comment utiliser les outils indispensables tels que les titres, tableaux, images, numérotation, en-têtes, pieds de page et la conversion en PDF.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">Maîtriser Word, c’est améliorer la qualité de vos travaux et gagner en efficacité dans la présentation de vos documents.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-1-introduction-a-word/\">Chapitre 1: introduction à Word</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-2-saisie-et-modification-de-texte/\">Chapitre 2: Saisie et modification de texte</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-3-mise-en-forme-du-document/\">Chapitre 3: Mise en forme de texte</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-4-mise-en-page-et-mise-en-forme-de-paragraphe/\">Chapitre 4: mise en page et mise en forme de paragraphe</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-5-insertion-dobjet/\">Chapitre 5: Insertion d\'objets</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-6-creation-de-tableux/\">Chapitre 6: création de Tableaux</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-7-en-tete-et-pied-de-page/\">Chapitre 7: En tête et Pied de Page</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 8: création de Facture Pro format</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 9: Création d\'une lettre et le Publipostage</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons -->','Microsoft Word','','inherit','closed','closed','','267-revision-v1','','','2026-04-06 10:37:42','2026-04-06 10:37:42','',267,'http://supboost.local/?p=352',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (353,1,'2026-04-06 11:58:34','0000-00-00 00:00:00','','Brouillon auto','','auto-draft','closed','closed','','','','','2026-04-06 11:58:34','0000-00-00 00:00:00','',0,'http://supboost.local/?page_id=353',0,'page','',0);
INSERT INTO `wp_posts` VALUES (354,1,'2026-04-06 12:02:54','2026-04-06 12:02:54','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">I. Définition</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Une <strong>facture pro forma</strong> est un document commercial provisoire qui ressemble à une facture normale, mais qui <strong>n’a pas valeur de facture définitive</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Elle sert à :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>informer le client du prix</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>présenter les produits ou services</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>préciser les conditions de vente</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>servir de devis détaillé</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Elle est très utilisée dans le commerce, la gestion et l’import-export.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">II. Importance de la facture pro forma</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Elle permet de :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>donner une estimation du coût</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>faciliter la commande</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>préparer la facture finale</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>rassurer le client</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">III. Création du document dans Word</h2>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1) Ouvrir un document vierge</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Ouvrir <strong>Microsoft Word</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur <strong>Nouveau document</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2) Saisir l’en-tête de l’entreprise</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>En haut de la page, écrire :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>nom de l’entreprise</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>adresse</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>téléphone</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>e-mail</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>logo</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>SUPBOOST SARL</strong><br>Dakar, Sénégal<br>Tél : 77 000 00 00<br>Email : <a>contact@supboost.com</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3) Écrire le titre</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Au centre de la page, écrire :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>FACTURE PRO FORMA</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Mettre le titre :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>en <strong>gras</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>taille <strong>16 ou 18</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>centré</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">4) Informations du client</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Écrire :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Client :</strong><br>Nom : __________________<br>Adresse : ______________<br>Téléphone : ____________</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">5) Références</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Ajouter :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Numéro : PF001</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Date : 06/04/2026</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Date limite : 10/04/2026</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">IV. Création du tableau</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Insérer un tableau de <strong>6 colonnes</strong> :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Insertion → Tableau → 6 colonnes</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Modèle</h3>\n<!-- /wp:heading -->\n\n<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><th>Désignation</th><th>Quantité</th><th>Prix unitaire</th><th>Montant HT</th><th>TVA</th><th>Montant TTC</th></tr></thead><tbody><tr><td>Clavier</td><td>2</td><td>5000</td><td>10000</td><td>1800</td><td>11800</td></tr><tr><td>Souris</td><td>1</td><td>3000</td><td>3000</td><td>540</td><td>3540</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">V. Calcul du montant HT</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le <strong>montant HT (Hors Taxe)</strong> représente le coût sans taxe.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Formule</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Montant HT = Quantité × Prix unitaire</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pour 2 claviers à 5 000 FCFA :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>HT = 2 × 5 000 = 10 000 FCFA</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Dans Word</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Cliquer dans la cellule HT puis :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Disposition → Formule</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">=PRODUCT(LEFT)</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:paragraph -->\n<p>Cette formule multiplie les valeurs situées à gauche.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VI. Calcul de la TVA</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>La <strong>TVA</strong> est la taxe appliquée sur le montant HT.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Formule</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>TVA = HT × taux de TVA</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Avec un taux de <strong>18 %</strong> :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>TVA = 10 000 × 0,18 = 1 800 FCFA</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Dans Word</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Cliquer dans la cellule TVA puis :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Disposition → Formule</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">=LEFT*0.18</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VII. Calcul du montant TTC</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le <strong>montant TTC (Toutes Taxes Comprises)</strong> est le montant final à payer.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Formule</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>TTC = HT + TVA</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>TTC = 10 000 + 1 800 = 11 800 FCFA</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Dans Word</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Cliquer dans la cellule TTC puis :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Disposition → Formule</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">=SUM(LEFT)</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VIII. Total général de la facture</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>En bas du tableau, ajouter :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Total HT</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>TVA totale</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Total TTC</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Total HT = 13 000 FCFA</strong><br><strong>TVA = 2 340 FCFA</strong><br><strong>Total TTC = 15 340 FCFA</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Pour additionner une colonne dans Word :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">=SUM(ABOVE)</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:paragraph -->\n<p>Cette formule additionne toutes les cellules au-dessus.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">IX. Copier ou déplacer un résultat</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Cette partie est très importante.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1) Copier un résultat</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pour recopier un montant dans une autre cellule :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>sélectionner la cellule</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Ctrl + C</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>cliquer dans la nouvelle cellule</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Ctrl + V</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2) Déplacer un résultat</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pour déplacer le résultat :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>sélectionner la cellule</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Ctrl + X</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>cliquer à l’endroit voulu</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Ctrl + V</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3) Mettre à jour les calculs</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Après modification des valeurs, appuyer sur :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>F9</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Cela met à jour les résultats.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">X. Mention obligatoire</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>En bas du document, écrire :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>NB : Ceci est une facture pro forma et ne constitue pas une facture définitive.</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">XI. Mise en forme professionnelle</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pour une bonne présentation :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>police : <strong>Times New Roman 12</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>titre en <strong>gras</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>tableau avec bordures</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>montants alignés à droite</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>total en gras</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:file {\"id\":355,\"href\":\"http://supboost.local/wp-content/uploads/2026/04/Chapitre-8-creation-dune-facture-pro-format.pdf\",\"displayPreview\":false} -->\n<div class=\"wp-block-file\"><a id=\"wp-block-file--media-bc03eb9d-bba1-48d3-906f-7c8c7a59b84c\" href=\"http://supboost.local/wp-content/uploads/2026/04/Chapitre-8-creation-dune-facture-pro-format.pdf\">Chapitre 8: création d\'une facture pro format</a><a href=\"http://supboost.local/wp-content/uploads/2026/04/Chapitre-8-creation-dune-facture-pro-format.pdf\" class=\"wp-block-file__button wp-element-button\" download aria-describedby=\"wp-block-file--media-bc03eb9d-bba1-48d3-906f-7c8c7a59b84c\">Télécharger le fichier PDF</a></div>\n<!-- /wp:file -->','Chapitre 8: création d\'une facture pro format','','publish','closed','closed','','chapitre-8-creation-dune-facture-pro-format','','','2026-04-06 12:02:55','2026-04-06 12:02:55','',0,'http://supboost.local/?page_id=354',0,'page','',0);
INSERT INTO `wp_posts` VALUES (355,1,'2026-04-06 12:01:24','2026-04-06 12:01:24','','Chapitre 8 création d\'une facture pro format','','inherit','open','closed','','chapitre-8-creation-dune-facture-pro-format','','','2026-04-06 12:01:24','2026-04-06 12:01:24','',354,'http://supboost.local/wp-content/uploads/2026/04/Chapitre-8-creation-dune-facture-pro-format.pdf',0,'attachment','application/pdf',0);
INSERT INTO `wp_posts` VALUES (356,1,'2026-04-06 12:02:05','2026-04-06 12:02:05','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">I. Définition</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Une <strong>facture pro forma</strong> est un document commercial provisoire qui ressemble à une facture normale, mais qui <strong>n’a pas valeur de facture définitive</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Elle sert à :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>informer le client du prix</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>présenter les produits ou services</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>préciser les conditions de vente</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>servir de devis détaillé</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Elle est très utilisée dans le commerce, la gestion et l’import-export.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">II. Importance de la facture pro forma</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Elle permet de :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>donner une estimation du coût</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>faciliter la commande</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>préparer la facture finale</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>rassurer le client</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">III. Création du document dans Word</h2>\n<!-- /wp:heading -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1) Ouvrir un document vierge</h3>\n<!-- /wp:heading -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Ouvrir <strong>Microsoft Word</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Cliquer sur <strong>Nouveau document</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2) Saisir l’en-tête de l’entreprise</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>En haut de la page, écrire :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>nom de l’entreprise</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>adresse</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>téléphone</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>e-mail</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>logo</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>SUPBOOST SARL</strong><br>Dakar, Sénégal<br>Tél : 77 000 00 00<br>Email : <a>contact@supboost.com</a></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3) Écrire le titre</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Au centre de la page, écrire :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>FACTURE PRO FORMA</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Mettre le titre :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>en <strong>gras</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>taille <strong>16 ou 18</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>centré</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">4) Informations du client</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Écrire :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Client :</strong><br>Nom : __________________<br>Adresse : ______________<br>Téléphone : ____________</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">5) Références</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Ajouter :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Numéro : PF001</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Date : 06/04/2026</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Date limite : 10/04/2026</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">IV. Création du tableau</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Insérer un tableau de <strong>6 colonnes</strong> :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Insertion → Tableau → 6 colonnes</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Modèle</h3>\n<!-- /wp:heading -->\n\n<!-- wp:table -->\n<figure class=\"wp-block-table\"><table class=\"has-fixed-layout\"><thead><tr><th>Désignation</th><th>Quantité</th><th>Prix unitaire</th><th>Montant HT</th><th>TVA</th><th>Montant TTC</th></tr></thead><tbody><tr><td>Clavier</td><td>2</td><td>5000</td><td>10000</td><td>1800</td><td>11800</td></tr><tr><td>Souris</td><td>1</td><td>3000</td><td>3000</td><td>540</td><td>3540</td></tr></tbody></table></figure>\n<!-- /wp:table -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">V. Calcul du montant HT</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le <strong>montant HT (Hors Taxe)</strong> représente le coût sans taxe.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Formule</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Montant HT = Quantité × Prix unitaire</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pour 2 claviers à 5 000 FCFA :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>HT = 2 × 5 000 = 10 000 FCFA</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Dans Word</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Cliquer dans la cellule HT puis :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Disposition → Formule</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">=PRODUCT(LEFT)</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:paragraph -->\n<p>Cette formule multiplie les valeurs situées à gauche.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VI. Calcul de la TVA</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>La <strong>TVA</strong> est la taxe appliquée sur le montant HT.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Formule</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>TVA = HT × taux de TVA</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Avec un taux de <strong>18 %</strong> :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>TVA = 10 000 × 0,18 = 1 800 FCFA</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Dans Word</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Cliquer dans la cellule TVA puis :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Disposition → Formule</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">=LEFT*0.18</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VII. Calcul du montant TTC</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Le <strong>montant TTC (Toutes Taxes Comprises)</strong> est le montant final à payer.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Formule</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>TTC = HT + TVA</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>TTC = 10 000 + 1 800 = 11 800 FCFA</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Dans Word</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Cliquer dans la cellule TTC puis :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>Disposition → Formule</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">=SUM(LEFT)</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VIII. Total général de la facture</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>En bas du tableau, ajouter :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li><strong>Total HT</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>TVA totale</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Total TTC</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">Exemple</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p><strong>Total HT = 13 000 FCFA</strong><br><strong>TVA = 2 340 FCFA</strong><br><strong>Total TTC = 15 340 FCFA</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Pour additionner une colonne dans Word :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">=SUM(ABOVE)</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:paragraph -->\n<p>Cette formule additionne toutes les cellules au-dessus.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">IX. Copier ou déplacer un résultat</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Cette partie est très importante.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1) Copier un résultat</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pour recopier un montant dans une autre cellule :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>sélectionner la cellule</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Ctrl + C</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>cliquer dans la nouvelle cellule</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Ctrl + V</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2) Déplacer un résultat</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pour déplacer le résultat :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>sélectionner la cellule</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Ctrl + X</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>cliquer à l’endroit voulu</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li><strong>Ctrl + V</strong></li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3) Mettre à jour les calculs</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Après modification des valeurs, appuyer sur :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>F9</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Cela met à jour les résultats.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">X. Mention obligatoire</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>En bas du document, écrire :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p><strong>NB : Ceci est une facture pro forma et ne constitue pas une facture définitive.</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">XI. Mise en forme professionnelle</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pour une bonne présentation :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>police : <strong>Times New Roman 12</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>titre en <strong>gras</strong></li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>tableau avec bordures</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>montants alignés à droite</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>total en gras</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:file {\"id\":355,\"href\":\"http://supboost.local/wp-content/uploads/2026/04/Chapitre-8-creation-dune-facture-pro-format.pdf\",\"displayPreview\":false} -->\n<div class=\"wp-block-file\"><a id=\"wp-block-file--media-bc03eb9d-bba1-48d3-906f-7c8c7a59b84c\" href=\"http://supboost.local/wp-content/uploads/2026/04/Chapitre-8-creation-dune-facture-pro-format.pdf\">Chapitre 8: création d\'une facture pro format</a><a href=\"http://supboost.local/wp-content/uploads/2026/04/Chapitre-8-creation-dune-facture-pro-format.pdf\" class=\"wp-block-file__button wp-element-button\" download aria-describedby=\"wp-block-file--media-bc03eb9d-bba1-48d3-906f-7c8c7a59b84c\">Télécharger le fichier PDF</a></div>\n<!-- /wp:file -->','Chapitre 8: création d\'une facture pro format','','inherit','closed','closed','','354-revision-v1','','','2026-04-06 12:02:05','2026-04-06 12:02:05','',354,'http://supboost.local/?p=356',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (357,1,'2026-04-06 12:03:50','2026-04-06 12:03:50','<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">La maîtrise de Microsoft Word est une compétence essentielle dans le parcours scolaire et professionnel. Ce logiciel permet de rédiger, mettre en forme et présenter des documents de manière claire, soignée et professionnelle. Grâce à ce cours, vous apprendrez à créer des devoirs, exposés, rapports, lettres, CV et fascicules avec une mise en page structurée et attractive. Vous découvrirez également comment utiliser les outils indispensables tels que les titres, tableaux, images, numérotation, en-têtes, pieds de page et la conversion en PDF.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">Maîtriser Word, c’est améliorer la qualité de vos travaux et gagner en efficacité dans la présentation de vos documents.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-1-introduction-a-word/\">Chapitre 1: introduction à Word</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-2-saisie-et-modification-de-texte/\">Chapitre 2: Saisie et modification de texte</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-3-mise-en-forme-du-document/\">Chapitre 3: Mise en forme de texte</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-4-mise-en-page-et-mise-en-forme-de-paragraphe/\">Chapitre 4: mise en page et mise en forme de paragraphe</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-5-insertion-dobjet/\">Chapitre 5: Insertion d\'objets</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-6-creation-de-tableux/\">Chapitre 6: création de Tableaux</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-7-en-tete-et-pied-de-page/\">Chapitre 7: En tête et Pied de Page</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-8-creation-dune-facture-pro-format/\">Chapitre 8: création de Facture Pro format</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 9: Création d\'une lettre et le Publipostage</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons -->','Microsoft Word','','inherit','closed','closed','','267-revision-v1','','','2026-04-06 12:03:50','2026-04-06 12:03:50','',267,'http://supboost.local/?p=357',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (358,1,'2026-04-09 15:56:45','2026-04-09 15:56:45','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Introduction</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Dans le domaine de l’informatique de gestion, il est essentiel de disposer d’une méthode claire pour analyser, organiser et concevoir les systèmes d’information. La méthode <strong>Merise</strong> fait partie des approches les plus utilisées pour structurer les données et les traitements.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Ce chapitre introductif permet de comprendre les notions fondamentales qui serviront de base pour la suite du cours.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">I. Définition de la méthode Merise</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Merise est une méthode d’<strong>analyse, de conception et de modélisation des systèmes d’information</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Elle permet de représenter de manière claire :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>les <strong>données</strong> à stocker ;</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>les <strong>traitements</strong> à effectuer ;</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>les <strong>relations</strong> entre les différents éléments du système.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Son objectif est de faciliter la création d’applications informatiques fiables et bien structurées.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">II. Importance de la méthode Merise</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>La méthode Merise est importante car elle permet de :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>mieux organiser les informations ;</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>éviter les répétitions inutiles des données ;</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>limiter les erreurs ;</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>faciliter la création des bases de données ;</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>améliorer la compréhension du système.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Elle est particulièrement utile dans les domaines de la gestion, de l’éducation, de la comptabilité et de l’administration.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">III. La notion de système</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Un système est un ensemble d’éléments organisés qui collaborent pour atteindre un objectif précis.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Dans un établissement scolaire, par exemple, les étudiants, les enseignants, les notes et les classes forment un système.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>On distingue généralement :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1. Le système opérant</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Il réalise les tâches.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemples :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>saisie des notes ;</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>inscription des étudiants ;</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>impression des relevés.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2. Le système de pilotage</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Il prend les décisions et contrôle le fonctionnement.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemples :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>direction ;</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>administration ;</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>service pédagogique.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3. Le système d’information</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Il assure la liaison entre les deux.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Il permet de :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>collecter les informations ;</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>stocker les données ;</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>traiter les informations ;</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>diffuser les résultats.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">IV. La notion de modèle</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Un modèle est une représentation simplifiée de la réalité.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>En Merise, on utilise des modèles pour représenter le système avant sa réalisation.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Par exemple, dans une école, on peut modéliser :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>Étudiant ;</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Classe ;</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Matière ;</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>Note.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:paragraph -->\n<p>Cette représentation facilite l’analyse et la conception.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">V. Séparation entre données et traitements</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>L’un des principes fondamentaux de Merise est la séparation entre les <strong>données</strong> et les <strong>traitements</strong>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1. Les données</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Ce sont les informations à mémoriser.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemples :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>nom ;</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>matricule ;</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>note ;</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>date.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2. Les traitements</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Ce sont les opérations effectuées sur les données.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemples :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:list -->\n<ul class=\"wp-block-list\"><!-- wp:list-item -->\n<li>calcul de moyenne ;</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>ajout d’un étudiant ;</li>\n<!-- /wp:list-item -->\n\n<!-- wp:list-item -->\n<li>modification d’une note.</li>\n<!-- /wp:list-item --></ul>\n<!-- /wp:list -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">VI. Les niveaux de modélisation</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>La méthode Merise repose sur plusieurs niveaux.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">1. Niveau conceptuel</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Il répond à la question : <strong>Quoi ?</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">2. Niveau logique</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Il répond à la question : <strong>Avec quelle structure ?</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading {\"level\":3} -->\n<h3 class=\"wp-block-heading\">3. Niveau physique</h3>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Il répond à la question : <strong>Comment ?</strong></p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Conclusion</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>En résumé, la méthode Merise constitue une base essentielle pour la conception des systèmes d’information.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Elle permet de structurer les données, d’organiser les traitements et de préparer efficacement la création d’une base de données ou d’une application.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:file {\"id\":359,\"href\":\"http://supboost.local/wp-content/uploads/2026/04/merise-1.pdf\",\"displayPreview\":false} -->\n<div class=\"wp-block-file\"><a id=\"wp-block-file--media-9c03dd66-86cf-4d91-8606-1eef3fc939ce\" href=\"http://supboost.local/wp-content/uploads/2026/04/merise-1.pdf\">chapitre 1: introduction à la méthode MERISE</a><a href=\"http://supboost.local/wp-content/uploads/2026/04/merise-1.pdf\" class=\"wp-block-file__button wp-element-button\" download aria-describedby=\"wp-block-file--media-9c03dd66-86cf-4d91-8606-1eef3fc939ce\">Télécharger le fichier PDF</a></div>\n<!-- /wp:file -->','chapitre I: introduction à la méthode MERISE','','publish','closed','closed','','chapitre-i-introduction-a-la-methode-merise','','','2026-04-09 15:56:45','2026-04-09 15:56:45','',0,'http://supboost.local/?page_id=358',0,'page','',0);
INSERT INTO `wp_posts` VALUES (359,1,'2026-04-09 15:55:42','2026-04-09 15:55:42','','merise  1','','inherit','open','closed','','merise-1','','','2026-04-09 15:55:42','2026-04-09 15:55:42','',358,'http://supboost.local/wp-content/uploads/2026/04/merise-1.pdf',0,'attachment','application/pdf',0);
