INSERT INTO `wp_posts` VALUES (373,1,'2026-04-09 17:12:38','2026-04-09 17:12:38','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Introduction</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pour qu’un programme soit utile, il doit pouvoir communiquer avec l’utilisateur. Cela implique de <strong>recevoir des informations</strong> (entrées) et de <strong>les afficher</strong> ou les traiter (sorties). En Python, il existe des fonctions simples et puissantes pour gérer ces interactions. Comprendre les entrées et sorties est essentiel pour créer des programmes interactifs et dynamiques.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Les sorties avec <code>print()</code></h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>La fonction principale pour afficher des informations à l’écran est <code>print()</code>. Elle permet de montrer du texte, des nombres, ou même le résultat de calculs. Par exemple :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">print(\"Bonjour, bienvenue sur Python\")<br>a = 5<br>b = 3<br>print(\"Le résultat de a + b est :\", a + b)</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:paragraph -->\n<p>Le résultat affiché sera :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">Bonjour, bienvenue sur Python<br>Le résultat de a + b est : 8</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:paragraph -->\n<p>La fonction <code>print()</code> peut afficher plusieurs valeurs à la fois, séparer du texte et des nombres, et même formater des messages clairs pour l’utilisateur.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Les entrées avec <code>input()</code></h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Pour recevoir des informations de l’utilisateur, Python utilise la fonction <code>input()</code>. Cette fonction affiche un message et attend que l’utilisateur saisisse quelque chose. La valeur saisie est toujours considérée comme une <strong>chaîne de caractères</strong> (<code>str</code>), même si l’utilisateur tape un nombre.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Par exemple :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">nom = input(\"Entrez votre nom : \")<br>print(\"Bonjour\", nom)</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:paragraph -->\n<p>Si l’utilisateur saisit <code>Babacar</code>, le programme affichera :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">Bonjour Babacar</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:paragraph -->\n<p>Pour utiliser la valeur saisie comme un nombre, il faut la <strong>convertir</strong> avec <code>int()</code> pour un entier ou <code>float()</code> pour un nombre décimal :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">age = int(input(\"Entrez votre âge : \"))<br>print(\"Dans 5 ans, vous aurez\", age + 5, \"ans\")</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Combiner entrées et sorties</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Les entrées et sorties peuvent être combinées pour créer des programmes interactifs qui effectuent des calculs, posent des questions ou affichent des résultats personnalisés. Par exemple :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">nom = input(\"Entrez votre nom : \")<br>age = int(input(\"Entrez votre âge : \"))<br>print(\"Bonjour\", nom, \"! Dans 10 ans, vous aurez\", age + 10, \"ans.\")</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:paragraph -->\n<p>Ce programme permet à l’utilisateur de saisir ses informations et de recevoir une réponse dynamique adaptée à sa saisie.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Conclusion</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Les entrées et sorties sont la base de l’interaction entre un programme et l’utilisateur. La fonction <code>print()</code> permet d’afficher des informations, tandis que <code>input()</code> permet de récupérer des données. La maîtrise de ces fonctions est essentielle pour développer des programmes interactifs et préparer les élèves à utiliser les conditions, les boucles et les fonctions dans les chapitres suivants.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:file {\"id\":372,\"href\":\"http://supboost.local/wp-content/uploads/2026/04/Phyton-3.pdf\",\"displayPreview\":false} -->\n<div class=\"wp-block-file\"><a id=\"wp-block-file--media-0c04d665-bba0-4da4-af97-9096741a4f39\" href=\"http://supboost.local/wp-content/uploads/2026/04/Phyton-3.pdf\">chapitre 3: les entrées et sorties dans phyton</a><a href=\"http://supboost.local/wp-content/uploads/2026/04/Phyton-3.pdf\" class=\"wp-block-file__button wp-element-button\" download aria-describedby=\"wp-block-file--media-0c04d665-bba0-4da4-af97-9096741a4f39\">Télécharger le fichier PDF</a></div>\n<!-- /wp:file -->','Chapitre 3: les entrées et sorties dans phyton','','inherit','closed','closed','','371-revision-v1','','','2026-04-09 17:12:38','2026-04-09 17:12:38','',371,'http://supboost.local/?p=373',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (374,1,'2026-04-09 17:13:31','2026-04-09 17:13:31','<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">Dans un monde de plus en plus numérique, la maîtrise de la programmation est devenue un véritable atout. Python, grâce à sa simplicité et à sa puissance, est aujourd’hui l’un des langages les plus demandés dans les domaines du développement web, de l’analyse de données, de l’intelligence artificielle et de la création d’applications.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-6\"}}}},\"textColor\":\"ast-global-color-6\"} -->\n<p class=\"has-ast-global-color-6-color has-text-color has-link-color\">Ce cours vous permettra de construire des bases solides en programmation, même si vous débutez totalement. À travers des explications claires et des exemples pratiques, vous développerez progressivement les compétences nécessaires pour comprendre, écrire et maîtriser vos premiers programmes. Commencer par Python, c’est faire le choix d’un apprentissage moderne, utile et porteur d’avenir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-1-introduction-a-phyton/\">Chapitre 1: introduction à Phyton </a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"className\":\"is-style-fill\",\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100 is-style-fill\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-2-les-variables-et-les-types-de-donnees/\">Chapitre 2: variables et types de données</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-3-les-entrees-et-sorties-dans-phyton/\">Chapitre 3: Entrée/sortie dans phyton</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 4: les opérateurs</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 5: les structures de conditions</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 6: les boucles</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 7: les listes</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 8: les dictionnaires</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons -->','phyton','','inherit','closed','closed','','253-revision-v1','','','2026-04-09 17:13:31','2026-04-09 17:13:31','',253,'http://supboost.local/?p=374',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (375,1,'2026-04-09 17:23:49','2026-04-09 17:23:49','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Introduction</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>En programmation, les opérateurs permettent de <strong>manipuler les valeurs</strong> et d’effectuer des calculs, des comparaisons ou des combinaisons de données. En Python, il existe plusieurs types d’opérateurs : arithmétiques, de comparaison, logiques et d’affectation. Comprendre leur fonctionnement est essentiel pour créer des programmes qui réalisent des calculs, prennent des décisions et contrôlent le déroulement des instructions.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">I. Les opérateurs arithmétiques</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Les opérateurs arithmétiques servent à effectuer des calculs mathématiques. Python reconnaît les principaux opérateurs : addition (+), soustraction (-), multiplication (*), division (/), division entière (//), modulo (%) et puissance (**).</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Par exemple :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">a = 10<br>b = 3print(\"Addition :\", a + b)<br>print(\"Soustraction :\", a - b)<br>print(\"Multiplication :\", a * b)<br>print(\"Division :\", a / b)<br>print(\"Division entière :\", a // b)<br>print(\"Modulo :\", a % b)<br>print(\"Puissance :\", a ** b)</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:paragraph -->\n<p>Ce programme affichera :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">Addition : 13<br>Soustraction : 7<br>Multiplication : 30<br>Division : 3.3333333333333335<br>Division entière : 3<br>Modulo : 1<br>Puissance : 1000</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:paragraph -->\n<p>Ces opérateurs sont utilisés pour toutes sortes de calculs dans les programmes.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">II. Les opérateurs de comparaison</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Les opérateurs de comparaison permettent de <strong>comparer des valeurs</strong> et de retourner un résultat booléen (<code>True</code> ou <code>False</code>). Les principaux opérateurs sont : égal à (==), différent de (!=), supérieur à (&gt;), inférieur à (&lt;), supérieur ou égal à (&gt;=) et inférieur ou égal à (&lt;=).</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemple :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">x = 5<br>y = 8print(x == y)   # False<br>print(x != y)   # True<br>print(x &gt; y)    # False<br>print(x &lt; y)    # True<br>print(x &gt;= 5)   # True<br>print(y &lt;= 10)  # True</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:paragraph -->\n<p>Les comparaisons sont indispensables dans les conditions et les décisions dans un programme.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">III. Les opérateurs logiques</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Les opérateurs logiques permettent de <strong>combiner plusieurs conditions</strong>. Les principaux sont : <code>and</code> (et), <code>or</code> (ou) et <code>not</code> (non).</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemple :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">a = True<br>b = Falseprint(a and b)  # False<br>print(a or b)   # True<br>print(not a)    # False</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:paragraph -->\n<p>Ces opérateurs sont utilisés pour créer des conditions complexes et contrôler le déroulement du programme.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">IV. Les opérateurs d’affectation</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Les opérateurs d’affectation permettent de <strong>modifier la valeur d’une variable</strong> en utilisant une opération. Le plus simple est <code>=</code> qui attribue une valeur, mais il existe aussi <code>+=</code>, <code>-=</code>, <code>*=</code>, <code>/=</code>, <code>//=</code>, <code>%=</code> et <code>**=</code>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemple :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">x = 10<br>x += 5   # équivalent à x = x + 5<br>x *= 2   # équivalent à x = x * 2<br>print(x) # 30</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:paragraph -->\n<p>Ces opérateurs simplifient les calculs et rendent le code plus lisible.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Conclusion</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Les opérateurs sont essentiels pour manipuler les valeurs et prendre des décisions dans un programme Python. Les opérateurs arithmétiques permettent de calculer, les opérateurs de comparaison et logiques permettent de contrôler le déroulement des instructions, et les opérateurs d’affectation facilitent la mise à jour des variables. La maîtrise de ces opérateurs est nécessaire pour aborder les prochaines notions comme les conditions et les boucles.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:file {\"id\":376,\"href\":\"http://supboost.local/wp-content/uploads/2026/04/phyton-4.pdf\",\"displayPreview\":false} -->\n<div class=\"wp-block-file\"><a id=\"wp-block-file--media-a9f16559-da11-4e82-bc01-5fee6427fede\" href=\"http://supboost.local/wp-content/uploads/2026/04/phyton-4.pdf\">Chapitre 4: les opérateurs en Phyton</a><a href=\"http://supboost.local/wp-content/uploads/2026/04/phyton-4.pdf\" class=\"wp-block-file__button wp-element-button\" download aria-describedby=\"wp-block-file--media-a9f16559-da11-4e82-bc01-5fee6427fede\">Télécharger le fichier PDF</a></div>\n<!-- /wp:file -->','chapitre 4: les opérateurs en  Phyton','','publish','closed','closed','','chapitre-4-les-operateurs-en-phyton','','','2026-04-09 17:23:50','2026-04-09 17:23:50','',0,'http://supboost.local/?page_id=375',0,'page','',0);
INSERT INTO `wp_posts` VALUES (376,1,'2026-04-09 17:22:41','2026-04-09 17:22:41','','phyton 4','','inherit','open','closed','','phyton-4','','','2026-04-09 17:22:41','2026-04-09 17:22:41','',375,'http://supboost.local/wp-content/uploads/2026/04/phyton-4.pdf',0,'attachment','application/pdf',0);
INSERT INTO `wp_posts` VALUES (377,1,'2026-04-09 17:23:49','2026-04-09 17:23:49','<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Introduction</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>En programmation, les opérateurs permettent de <strong>manipuler les valeurs</strong> et d’effectuer des calculs, des comparaisons ou des combinaisons de données. En Python, il existe plusieurs types d’opérateurs : arithmétiques, de comparaison, logiques et d’affectation. Comprendre leur fonctionnement est essentiel pour créer des programmes qui réalisent des calculs, prennent des décisions et contrôlent le déroulement des instructions.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">I. Les opérateurs arithmétiques</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Les opérateurs arithmétiques servent à effectuer des calculs mathématiques. Python reconnaît les principaux opérateurs : addition (+), soustraction (-), multiplication (*), division (/), division entière (//), modulo (%) et puissance (**).</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Par exemple :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">a = 10<br>b = 3print(\"Addition :\", a + b)<br>print(\"Soustraction :\", a - b)<br>print(\"Multiplication :\", a * b)<br>print(\"Division :\", a / b)<br>print(\"Division entière :\", a // b)<br>print(\"Modulo :\", a % b)<br>print(\"Puissance :\", a ** b)</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:paragraph -->\n<p>Ce programme affichera :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">Addition : 13<br>Soustraction : 7<br>Multiplication : 30<br>Division : 3.3333333333333335<br>Division entière : 3<br>Modulo : 1<br>Puissance : 1000</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:paragraph -->\n<p>Ces opérateurs sont utilisés pour toutes sortes de calculs dans les programmes.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">II. Les opérateurs de comparaison</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Les opérateurs de comparaison permettent de <strong>comparer des valeurs</strong> et de retourner un résultat booléen (<code>True</code> ou <code>False</code>). Les principaux opérateurs sont : égal à (==), différent de (!=), supérieur à (&gt;), inférieur à (&lt;), supérieur ou égal à (&gt;=) et inférieur ou égal à (&lt;=).</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemple :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">x = 5<br>y = 8print(x == y)   # False<br>print(x != y)   # True<br>print(x &gt; y)    # False<br>print(x &lt; y)    # True<br>print(x &gt;= 5)   # True<br>print(y &lt;= 10)  # True</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:paragraph -->\n<p>Les comparaisons sont indispensables dans les conditions et les décisions dans un programme.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">III. Les opérateurs logiques</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Les opérateurs logiques permettent de <strong>combiner plusieurs conditions</strong>. Les principaux sont : <code>and</code> (et), <code>or</code> (ou) et <code>not</code> (non).</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemple :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">a = True<br>b = Falseprint(a and b)  # False<br>print(a or b)   # True<br>print(not a)    # False</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:paragraph -->\n<p>Ces opérateurs sont utilisés pour créer des conditions complexes et contrôler le déroulement du programme.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">IV. Les opérateurs d’affectation</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Les opérateurs d’affectation permettent de <strong>modifier la valeur d’une variable</strong> en utilisant une opération. Le plus simple est <code>=</code> qui attribue une valeur, mais il existe aussi <code>+=</code>, <code>-=</code>, <code>*=</code>, <code>/=</code>, <code>//=</code>, <code>%=</code> et <code>**=</code>.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph -->\n<p>Exemple :</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:preformatted -->\n<pre class=\"wp-block-preformatted\">x = 10<br>x += 5   # équivalent à x = x + 5<br>x *= 2   # équivalent à x = x * 2<br>print(x) # 30</pre>\n<!-- /wp:preformatted -->\n\n<!-- wp:paragraph -->\n<p>Ces opérateurs simplifient les calculs et rendent le code plus lisible.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:separator -->\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n<!-- /wp:separator -->\n\n<!-- wp:heading -->\n<h2 class=\"wp-block-heading\">Conclusion</h2>\n<!-- /wp:heading -->\n\n<!-- wp:paragraph -->\n<p>Les opérateurs sont essentiels pour manipuler les valeurs et prendre des décisions dans un programme Python. Les opérateurs arithmétiques permettent de calculer, les opérateurs de comparaison et logiques permettent de contrôler le déroulement des instructions, et les opérateurs d’affectation facilitent la mise à jour des variables. La maîtrise de ces opérateurs est nécessaire pour aborder les prochaines notions comme les conditions et les boucles.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:file {\"id\":376,\"href\":\"http://supboost.local/wp-content/uploads/2026/04/phyton-4.pdf\",\"displayPreview\":false} -->\n<div class=\"wp-block-file\"><a id=\"wp-block-file--media-a9f16559-da11-4e82-bc01-5fee6427fede\" href=\"http://supboost.local/wp-content/uploads/2026/04/phyton-4.pdf\">Chapitre 4: les opérateurs en Phyton</a><a href=\"http://supboost.local/wp-content/uploads/2026/04/phyton-4.pdf\" class=\"wp-block-file__button wp-element-button\" download aria-describedby=\"wp-block-file--media-a9f16559-da11-4e82-bc01-5fee6427fede\">Télécharger le fichier PDF</a></div>\n<!-- /wp:file -->','chapitre 4: les opérateurs en  Phyton','','inherit','closed','closed','','375-revision-v1','','','2026-04-09 17:23:49','2026-04-09 17:23:49','',375,'http://supboost.local/?p=377',0,'revision','',0);
INSERT INTO `wp_posts` VALUES (378,1,'2026-04-09 17:25:14','2026-04-09 17:25:14','<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-8\"}}}},\"textColor\":\"ast-global-color-8\"} -->\n<p class=\"has-ast-global-color-8-color has-text-color has-link-color\">Dans un monde de plus en plus numérique, la maîtrise de la programmation est devenue un véritable atout. Python, grâce à sa simplicité et à sa puissance, est aujourd’hui l’un des langages les plus demandés dans les domaines du développement web, de l’analyse de données, de l’intelligence artificielle et de la création d’applications.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:paragraph {\"style\":{\"elements\":{\"link\":{\"color\":{\"text\":\"var:preset|color|ast-global-color-6\"}}}},\"textColor\":\"ast-global-color-6\"} -->\n<p class=\"has-ast-global-color-6-color has-text-color has-link-color\">Ce cours vous permettra de construire des bases solides en programmation, même si vous débutez totalement. À travers des explications claires et des exemples pratiques, vous développerez progressivement les compétences nécessaires pour comprendre, écrire et maîtriser vos premiers programmes. Commencer par Python, c’est faire le choix d’un apprentissage moderne, utile et porteur d’avenir.</p>\n<!-- /wp:paragraph -->\n\n<!-- wp:buttons -->\n<div class=\"wp-block-buttons\"><!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-1-introduction-a-phyton/\">Chapitre 1: introduction à Phyton </a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"className\":\"is-style-fill\",\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100 is-style-fill\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-2-les-variables-et-les-types-de-donnees/\">Chapitre 2: variables et types de données</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-3-les-entrees-et-sorties-dans-phyton/\">Chapitre 3: Entrée/sortie dans phyton</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\" href=\"http://supboost.local/chapitre-4-les-operateurs-en-phyton/\">Chapitre 4: les opérateurs en Phyton</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 5: les structures de conditions</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 6: les boucles</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 7: les listes</a></div>\n<!-- /wp:button -->\n\n<!-- wp:button {\"width\":100,\"fontSize\":\"large\"} -->\n<div class=\"wp-block-button has-custom-width wp-block-button__width-100\"><a class=\"wp-block-button__link has-large-font-size has-custom-font-size wp-element-button\">Chapitre 8: les dictionnaires</a></div>\n<!-- /wp:button --></div>\n<!-- /wp:buttons -->','phyton','','inherit','closed','closed','','253-revision-v1','','','2026-04-09 17:25:14','2026-04-09 17:25:14','',253,'http://supboost.local/?p=378',0,'revision','',0);
